INSERT INTO public.photos VALUES (25473, 'Puerta del Carmen c.1900', 'Puerta del Carmen como acceso a la calle de la Soberanâ”œآ،a Nacional, hacia donde se dirige el vehâ”œآ،culo. A la izquierda, el convento de la Encarnaciâ”œâ”‚n. Postal editada por "Casa Cesaraugusta" (Zaragoza), hacia 1905, utilizando una imagen previa de Hauser y Menet, capturada hacia 1900. Fuente visual: www.todocoleccion.net/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64985800, -0.88766100, '0101000020E6100000B4E89D0AB867ECBFA185048C2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25964327635.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25964327635.webp', 'https://www.flickr.com/photos/zaragozaantigua/25964327635/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25475, 'Depâ”œâ”‚sito de Cadâ”œأ­veres 1879', 'Desde 1842, la ciudad tenâ”œآ،a su depâ”œâ”‚sito judicial de cadâ”œأ­veres en una modesta caseta construida sobre un solar municipal en la calle de la Reina, entre la puerta del Carmen y el colegio homâ”œâ”‚nimo. En 1857, la Hermandad de la Sangre de Cristo proyectâ”œâ”‚ un edificio de nueva planta en esa misma ubicaciâ”œâ”‚n, sufragado por suscripciâ”œâ”‚n popular, con capilla y sala para realizar autopsias, o "losa", denominaciâ”œâ”‚n que tambiâ”œآ®n era utilizada vulgarmente como sinâ”œâ”‚nimo de depâ”œâ”‚sito de cadâ”œأ­veres. Desempeâ”œâ–’arâ”œآ،a esas funciones hasta entrado el siglo XX, cuando por encargo municipal el arquitecto Ricardo Magdalena diseâ”œâ–’â”œâ”‚ un nuevo depâ”œâ”‚sito judicial de cadâ”œأ­veres en el camino de los Cubos, en las traseras de las facultades de Medicina y Ciencias, y el hospital Clâ”œآ،nico, que fue inaugurado en 1908. En el plano, correspondiente con el realizado por Dioniso Casaâ”œâ–’al en 1879, hemos coloreado en pajizo la ubicaciâ”œâ”‚n del antiguo depâ”œâ”‚sito de cadâ”œأ­veres en la calle de la Reina, luego de la puerta del Carmen, y desde 1868, de la Soberanâ”œآ،a Nacional, junto al fielato de la puerta del Carmen, frente a la huerta del convento de la Encarnaciâ”œâ”‚n, y al sur de la escuela de Veterinaria y el cuartel del Carmen. Fuente: Ramâ”œâ”‚n Betrâ”œأ­n Abadâ”œآ،a, "La Ciudad y los muertos. La formaciâ”œâ”‚n del Cementerio de Torrero" (2015)', 1879, 1879, 1879, 'Siglo XIX', 'CENTRO', 41.65015800, -0.88710100, '0101000020E6100000F5F6E7A22163ECBFCB9D996038D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28255845010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28255845010.webp', 'https://www.flickr.com/photos/zaragozaantigua/28255845010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25476, 'Puerta del Carmen 1873', 'Grabado que representa el paso ante la Puerta del Carmen de presos carlistas conducidos a Zaragoza en el marco de la tercera guerra carlista del siglo XIX (1872-1876). Tras la puerta se divisa la Torre Nueva. Fuente visual: "Aragâ”œâ”‚n durante la primera Repâ”œâ•‘blica (1873)", Isidoro Berdiâ”œآ®, Zaragoza, 1992.', 1873, 1873, 1873, 'Siglo XIX', 'CENTRO', 41.64987200, -0.88769500, '0101000020E6100000B9533A58FF67ECBF064B75012FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29681279985.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29681279985.webp', 'https://www.flickr.com/photos/zaragozaantigua/29681279985/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25478, 'P.â”¬â•‘ de Pamplona 1963', 'Imagen capturada junto a la puerta del Carmen, con una interesante vista del paseo de Pamplona fluidificado para la circulaciâ”œâ”‚n rodada, que al fondo alcanza hasta el arranque del paseo de las Damas, y su destacado entorno colegial, a izquierda, y a derecha. Una unidad BUT de dos pisos, de la trolebusera lâ”œآ،nea "Ciudad Jardâ”œآ،n", acomete la rotonda de la puerta del Carmen para embocar luego hacia la calle Hernâ”œأ­n Cortâ”œآ®s. Fuente visual: www.delcampe.es', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64988000, -0.88767300, '0101000020E6100000C5591135D167ECBF892991442FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31155544003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31155544003.webp', 'https://www.flickr.com/photos/zaragozaantigua/31155544003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25479, 'Puerta del Carmen c.1946', 'Invernal imagen de la puerta del Carmen, aislada en una isleta con pequeâ”œâ–’a barandilla en la confluencia del paseo de Pamplona, el de Marâ”œآ،a Agustâ”œآ،n, y las calles General Sanjurjo y Hernâ”œأ­n Cortâ”œآ®s. Al fondo, los muros que delimitaban el antiguo convento y extensa huerta de las MM. Carmelitas de la Encarnaciâ”œâ”‚n, cuya iglesia asoma por la derecha. Su achaflanada esquina parece ser una buena solana para sobrellevar el fresco, si no hace cierzo. Al fondo, a la izquierda, el Hospicio, u Hogar Pignatelli. El despejado â”œأ­rbol de primer plano, integrante del andador central peatonal del paseo de Pamplona.', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64994900, -0.88766500, '0101000020E61000000FB9196EC067ECBFB188618731D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31255018141.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31255018141.webp', 'https://www.flickr.com/photos/zaragozaantigua/31255018141/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25480, 'Vista aâ”œآ®rea paseo Pamplona 1957', 'Vista aâ”œآ®rea del paseo de Pamplona y su entorno, con el paseo de Marâ”œآ،a Agustâ”œآ،n abajo. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64994900, -0.88766500, '0101000020E61000000FB9196EC067ECBFB188618731D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31321489226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31321489226.webp', 'https://www.flickr.com/photos/zaragozaantigua/31321489226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25481, 'P.â”¬â•‘ de Mâ”¬آ¬ Agustâ”œآ،n 2012', 'Con la excusa de la crisis econâ”œâ”‚mica iniciada en 2008, el gobierno del PSOE efectuâ”œâ”‚ una reforma laboral en 2010, dinamitando el Estatuto de los Trabajadores de 1980 y comenzando una caâ”œآ،da libre hacia la pâ”œآ®rdida de los derechos adquiridos. En 2012, el reciente gobierno del Partido Popular, con el supuesto propâ”œâ”‚sito de "acabar con la rigidez del mercado de trabajo", aprobâ”œâ”‚ una nueva reforma laboral, conocida como "decretazo", que suponâ”œآ،a una "profunda modernizaciâ”œâ”‚n de la legislaciâ”œâ”‚n laboral". En la vista aâ”œآ®rea, sobrevolando el convento de la Encarnaciâ”œâ”‚n (izquierda): en primer plano, paseo de Marâ”œآ،a Agustâ”œآ،n; al fondo, paseo de Pamplona. Por ahâ”œآ، discurre la manifestaciâ”œâ”‚n celebrada en Zaragoza el domingo 19 de febrero de 2012, en el marco de las movilizaciones contra la reforma laboral del PP, que concluyeron con una huelga general el 29 de marzo. La legislaciâ”œâ”‚n antiobrera se mantuvo. Fuente visual: elventano.es', 2012, 2012, 2012, 'Siglo XXI', 'CENTRO', 41.65004500, -0.88805100, '0101000020E610000059C345EEE96AECBFD3F6AFAC34D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31622671266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31622671266.webp', 'https://www.flickr.com/photos/zaragozaantigua/31622671266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25482, 'Puerta del Carmen 2008', 'Foto: Josâ”œآ® Miguel Marco. Puerta del Carmen, con la avenida de Câ”œآ®sar Augusto al fondo, en mayo de 2008, durante sus obras de restauraciâ”œâ”‚n. En 1908 fue declarada monumento nacional; en 1927 quedâ”œâ”‚ aislada, al demolerse sus edificios contiguos; en 1963, 1973 y 1997 se restaurâ”œâ”‚. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.64988000, -0.88767300, '0101000020E6100000C5591135D167ECBF892991442FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32639840591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32639840591.webp', 'https://www.flickr.com/photos/zaragozaantigua/32639840591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25483, 'Arzobispo Domâ”œآ®nech 1951', 'Rigoberto Domâ”œآ®nech, arzobispo de Zaragoza entre 1924 y 1955, durante los actos de bendiciâ”œâ”‚n de la iglesia y convento de los Carmelitas Calzados, en la calle del General Sanjurjo 7, el 3 de enero de 1951. Se trataba de la entrega de la casa contigua a la iglesia, "con rica ornamentaciâ”œâ”‚n", en la que se emprendâ”œآ،an obras de adaptaciâ”œâ”‚n. La nueva iglesia y colegio mayor del Carmen en el paseo de Marâ”œآ،a Agustâ”œآ،n sustituyeron aâ”œâ–’os despuâ”œآ®s, en el paseo de Marâ”œآ،a Agustâ”œآ،n, al antiguo complejo carmelita. Fuente visual: www.todocoleccion.net', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65040900, -0.88760900, '0101000020E6100000155454FD4A67ECBF1503249A40D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32646866165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32646866165.webp', 'https://www.flickr.com/photos/zaragozaantigua/32646866165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25484, 'Puerta del Carmen 1808', 'Recreaciâ”œâ”‚n de la Puerta del Carmen en los Sitios. Fuente: Documental "Zaragoza, ciudad sitiada" (Josâ”œآ® Manuel Herraiz y Pablo Lozano, 2009).', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64985600, -0.88767300, '0101000020E6100000C5591135D167ECBF008E3D7B2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33035987492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33035987492.webp', 'https://www.flickr.com/photos/zaragozaantigua/33035987492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25485, 'Puerta del Carmen c.1957', 'Imagen capturada desde cierta altura de la Puerta del Carmen y el arranque del paseo de Marâ”œآ،a Agustâ”œآ،n, en el momento en que un trolebâ”œâ•‘s BUT de un piso de la lâ”œآ،nea "Terminillo", estâ”œأ­ realizando el giro para embocar la calle de Hernâ”œأ­n Cortâ”œآ®s en la rotonda central entonces existente. La notoria ausencia de trâ”œأ­fico rodado facilita la maniobra, y el paso de peatones se hace con insâ”œâ”‚lita libertad y tranquilidad, visto desde hoy. El paseo de Marâ”œآ،a Agustâ”œآ،n mantiene su andador central, si bien de anchura bastante mâ”œأ­s reducida que el del paseo de Pamplona, a la izquierda, fuera de plano. Los edificios del frente son los del arranque del paseo Marâ”œآ،a Agustâ”œآ،n, en el lado de los impares, y entre ellos destaca el antiguo nâ”¬â•‘ 5, desaparecido y sustituido mâ”œأ­s tarde por otro edificio mâ”œأ­s moderno y alto. El luminoso nâ”¬â•‘ 11, esquinero con la calle del Capitâ”œأ­n Esponera, supera en altura a los siguientes edificios de forma seâ”œâ–’alada. Luego, serâ”œأ­ â”œآ®l el superado por ellos, por el doble de altura, cuando menos. Fuente visual: tarjeta postal ediciones DARVI (Zaragoza), en www.todocoleccion.net/', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64985600, -0.88767300, '0101000020E6100000C5591135D167ECBF008E3D7B2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33324253654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33324253654.webp', 'https://www.flickr.com/photos/zaragozaantigua/33324253654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25486, 'Puerta del Carmen 1890', 'Imagen de la "Puerta de Nuestra Seâ”œâ–’ora del Câ”œأ­rmen" (sic), asociada a un episodio menor de los asedios de 1808-09 convertido en leyenda del folclore local. La puerta todavâ”œآ،a conserva las hojas de madera, una en cada uno de los vanos laterales, y una doble para el gran hueco central. Por ella se accede a la calle de la Soberanâ”œآ،a Nacional. A la izquierda, muros de la huerta del convento de la Encarnaciâ”œâ”‚n, de las MM. Carmelitas calzadas. Fuente visual: أ”أ‡آ£Zaragoza Artâ”œآ،stica, Monumental e Histâ”œâ”‚ricaأ”أ‡أک, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64985600, -0.88767300, '0101000020E6100000C5591135D167ECBF008E3D7B2ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33834458464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33834458464.webp', 'https://www.flickr.com/photos/zaragozaantigua/33834458464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25489, 'P.â”¬â•‘ de Pamplona 1962', 'Imagen capturada junto a la puerta del Carmen, con una interesante y despejada vista del moderno paseo de Pamplona fluidificado recientemente en beneficio de la circulaciâ”œâ”‚n rodada. Hacia el fondo la vista alcanza hasta el arranque del paseo de las Damas y su destacado entorno colegial tanto a izquierda (El Salvador e iglesia de la Madre del Salvador), como a derecha (Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s). Una unidad BUT de dos pisos de la trolebusera lâ”œآ،nea "Ciudad Jardâ”œآ،n" retorna hacia la terminal de la plaza de Santa Engracia. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64888300, -0.88701600, '0101000020E610000068EBE0606F62ECBF16F71F990ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43711937864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43711937864.webp', 'https://www.flickr.com/photos/zaragozaantigua/43711937864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25490, 'Pâ”¬â•‘. de Pamplona 1962', 'Imagen capturada durante el arrasamiento del bulevar del paseo de Pamplona para dar vâ”œآ،a libre al trâ”œأ­fico rodado, una iniciativa realizada poco despuâ”œآ®s de la transformaciâ”œâ”‚n del paseo de la Independencia en una autopista urbana. La escena del derribo de â”œأ­rboles y arranque de mobiliario urbano, tiene como fondo edilicio la manzana delimitada entre las calles de Almagro y del Doctor Cerrada, quedando mâ”œأ­s al fondo las Facultades de Medicina y Ciencias, y el Edificio Elâ”œآ،seos, ya en la plaza de Basilio Paraâ”œآ،so.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64890500, -0.88708100, '0101000020E61000002EE57CB1F762ECBFFE9AAC510FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47722392992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47722392992.webp', 'https://www.flickr.com/photos/zaragozaantigua/47722392992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25491, 'Miralbueno c.1900', 'Inâ”œآ®dita e interesante imagen capturada desde la altura del torreâ”œâ”‚n del nuevo edificio de las Facultades de Medicina y Ciencias de la Universidad de Zaragoza. La vista estâ”œأ­ orientada hacia el despejado oeste de la ciudad, tâ”œآ®rmino de Miralbueno. En primer tâ”œآ®rmino y a la derecha, dos de los lavaderos ubicados en el tramo entre el camino de los Cubos y el paseo de los Capuchinos, y el Parador del Norte. En el centro, el huerto de Castellvâ”œآ، y la Torre de Joaquâ”œآ،n Pascual, inmediatos al cuartel de Hernâ”œأ­n Cortâ”œآ®s, que queda a la izquierda, aunque fuera de plano. Hacia el fondo y a la derecha, la Fundiciâ”œâ”‚n de Mercier en su primera ubicaciâ”œâ”‚n, casi esquinera con el arranque de la carretera de Zaragoza a Teruel. Ademâ”œأ­s, vista parcial del Hospicio Provincial y traseras del cuartel de Trinitarios. En el centro, despejados terrenos propiedad de la Empresa del Ferrocarril de MZA, incluyendo buena parte del Campo del Sepulcro.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64833600, -0.88815400, '0101000020E61000007FF8F9EFC16BECBFE4688EACFCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50731166336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50731166336.webp', 'https://www.flickr.com/photos/zaragozaantigua/50731166336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25493, 'Puerta del Carmen c.1885', 'Imagen capturada a extramuros de la ciudad y centrada en la Puerta del Carmen en la tradicional confluencia del camino de los Capuchinos (a espaldas del fotâ”œâ”‚grafo), el paseo de la Lealtad (derecha), el paseo de Marâ”œآ،a Agustâ”œآ،n (izquierda) y la calle de la Soberanâ”œآ،a Nacional que hacia el fondo nos lleva hasta la Torre Nueva desmochada de su barroco triple chapitel, pasando a la izquierda por el convento y huertas de la Encarnaciâ”œâ”‚n y por la derecha por el lavadero de Pignatelli, el Depâ”œâ”‚sito de Cadâ”œأ­veres y la Escuela de Veterinaria, hasta el despartidero donde continâ”œâ•‘a hacia la derecha hasta la plaza del Pueblo y la calle del Hospital arranca hacia la izquierda.', 1885, 1885, 1885, 'Siglo XIX', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52284951500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52284951500.webp', 'https://www.flickr.com/photos/zaragozaantigua/52284951500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
