INSERT INTO public.photos VALUES (25498, 'Puerta del Carmen c.1936', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. Aâ”œâ–’os 30. "Puerta del Carmen." Imagen de perfil, con visual de las apetitosas naves del Paseo de Pamplona.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65048400, -0.88771400, '0101000020E61000006971C6302768ECBF1F49490F43D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15160305586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15160305586.webp', 'https://www.flickr.com/photos/zaragozaantigua/15160305586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25499, 'Paseo de Pamplona 1928', 'Foto aâ”œآ®rea tomada desde un Farman del paseo de Pamplona de Zaragoza. A la derecha, puerta del Carmen. Fuente: Archivo Gâ”œâ”‚mez Laguna.', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64924000, -0.88725700, '0101000020E6100000D0B4C4CA6864ECBFA5A0DB4B1AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15165957625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15165957625.webp', 'https://www.flickr.com/photos/zaragozaantigua/15165957625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23135, 'Estaciâ”œâ”‚n Zaragoza Plaza 2006', 'Infografâ”œآ،a de la fachada exterior de la proyectada estaciâ”œâ”‚n del AVE Zaragoza Plaza, en las inmediaciones del nuevo barrio de Arcosur, la Feria de Muestras y la Plataforma Logâ”œآ،stica de Zaragoza (PLAZA). Esta segunda estaciâ”œâ”‚n del tren de Alta Velocidad en Zaragoza vio construida su primera fase entre 2006 y 2011, aâ”œâ–’o en que fue descartada, tanto en su faceta de apeadero del AVE como en la de cercanâ”œآ،as. En 2016 se iniciaba de nuevo el estudio de esta estaciâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.61722600, -0.96101100, '0101000020E6100000871403249AC0EEBFD61EF64201CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31804416931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31804416931.webp', 'https://www.flickr.com/photos/zaragozaantigua/31804416931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25502, 'Puerta del Carmen 1939', 'El 2 de mayo de 1939 se celebraron dos actos organizados por la Secciâ”œâ”‚n Juvenil de FET y de las JONS para conmemorar la universal fecha del 2 de mayo (de 1808). El primero, una misa de campaâ”œâ–’a ante la Puerta del Carmen, con presencia de las organizaciones juveniles del Râ”œآ®gimen franquista (Flechas, Pelayos, Cadetes), ademâ”œأ­s de autoridades militares y civiles, y pâ”œâ•‘blico. El segundo, una escenificaciâ”œâ”‚n dramatizada del relevo de la guardia ante la puerta, mientras un "Flecha" leâ”œآ،a elogios al 2 de mayo (de 1808). Luego leyâ”œâ”‚ discurso un concejal en nombre del Alcalde. Luego, el jefe provincial de la Falange, seâ”œâ–’or Muro. Luego, el jefe de la Quinta regiâ”œâ”‚n militar, general Raâ”œâ–’oy. Finalmente, desfilaron las organizaciones juveniles. Menudo fiestorro, en los dos sentidos. En la imagen, la Puerta del Carmen engalanada para la ocasiâ”œâ”‚n. A la izquierda, el antiguo convento de la Encarnaciâ”œâ”‚n de las Madres Carmelitas. Al fondo, la câ”œâ•‘pula de la parroquia de San Ildefonso, junto al Hospital Militar. Fuente visual: javierbarreiro.wordpress.com/category/sin-clasificar/', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64977300, -0.88758800, '0101000020E6100000384E0AF31E67ECBF7369FCC22BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15335301989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15335301989.webp', 'https://www.flickr.com/photos/zaragozaantigua/15335301989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25503, 'Puerta del Carmen 1940', '"Puerta del Carmen. Acto de propaganda en homenaje a los caâ”œآ،dos." Para llevar a cabo las celebraciones del 29 de octubre, dâ”œآ،a de los Caâ”œآ،dos (falangistas y, por extensiâ”œâ”‚n, nacionalistas), se escogiâ”œâ”‚ en 1938 la Puerta del Carmen como lugar emblemâ”œأ­tico y sâ”œآ،mbolo de la resistencia de la ciudad frente a los franceses. Para ello, se levantâ”œâ”‚ en el eje del vano central de la puerta una gran cruz, a los pies de la cual se depositaron un gran nâ”œâ•‘mero de coronas de flores rojas y amarillas, tras ella y sobre el vano central de la puerta, se leâ”œآ،a en grandes letras: "Presente". A ambos lados de la cruz, dos grandes pebeteros despedâ”œآ،an columnas de humo y sobre los portillos de los lados habâ”œآ،an sido colocadas coronas de laurel con lazos de los colores nacionalistas. Tambiâ”œآ®n se situaron a los lados cuatro falangistas con fusiles, y los abanderados de la Casa del Fascio (Italia) y de la Colonia Alemana, con sus respectivas banderas, todos ellos inmâ”œâ”‚viles junto a la cruz. Esto fue asâ”œآ، hasta que el "Altar de la Patria", luego redenominado "Monumento a los Hâ”œآ®roes y Mâ”œأ­rtires de Nuestra Gloriosa Cruzada", fue terminado en 1954... Mientras tanto, tanto italianos como alemanes, por circunstancias que no vienen al caso, desaparecieron de las celebraciones. Fuente visual: www1.dpz.es/cultura/agenda/2006/04/abril06-1.htm Fuente escrita: www.unizar.es/artigrama/pdf/24/3varia/13.pdf', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.64979500, -0.88763400, '0101000020E61000004E2A1A6B7F67ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380451099.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380451099.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380451099/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25510, 'Puerta del Carmen 1939', 'Dibujo de Borobio y Beltrâ”œأ­n como proyecto de remodelaciâ”œâ”‚n de la zona de la Puerta del Carmen. No llegâ”œâ”‚ a realizarse. Fuente visual: AMZ.', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20463958893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20463958893.webp', 'https://www.flickr.com/photos/zaragozaantigua/20463958893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25511, 'Puerta del Carmen 1934', 'Puerta del Carmen. A la izquierda, la iglesia y convento de las MM. Carmelitas de la Encarnaciâ”œâ”‚n. Al fondo, la calle de la Soberanâ”œآ،a Nacional. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22615351584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22615351584.webp', 'https://www.flickr.com/photos/zaragozaantigua/22615351584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25512, 'Puerta del Carmen c.1942', 'Imagen de la Puerta del Carmen, aislada en una isleta con pequeâ”œâ–’a barandilla. Al fondo, los chaflaneros muros que delimitaban la iglesia y convento de las MM. Carmelitas de la Encarnaciâ”œâ”‚n. A su derecha, la antigua calle de la Soberanâ”œآ،a Nacional, entonces recientemente redenominada "General Sanjurjo". A su izquierda, el paseo de Marâ”œآ،a Agustâ”œآ،n. Los â”œأ­rboles de primer plano, del amplio andâ”œآ®n central peatonal del paseo de Pamplona. Fuente visual: Familia Cuyâ”œأ،s (cartotecadigital.icc.cat/)', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24000143364.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24000143364.webp', 'https://www.flickr.com/photos/zaragozaantigua/24000143364/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25514, 'Puerta del Carmen c.1923', 'Vista de la Puerta del Carmen desde la calle de la Soberanâ”œآ،a Nacional. Tras ella, el paseo de Marâ”œآ،a Agustâ”œآ،n. Fuente: Foto Jesâ”œâ•‘s Cormâ”œأ­n. AMZ.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.64998600, -0.88746800, '0101000020E61000008FE3874A2366ECBFCE6DC2BD32D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24889006186.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24889006186.webp', 'https://www.flickr.com/photos/zaragozaantigua/24889006186/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25517, 'Puerta del Carmen c.1946', 'Vista de la puerta del Carmen desde afuera, con la calle del General Sanjurjo detrâ”œأ­s. A la izquierda, el convento de la Encarnaciâ”œâ”‚n. Fuente: www.facebook.com/photo.php?fbid=1516482491721047&set=...', 1946, 1946, 1946, 'Anos 40', 'CENTRO', 41.64987200, -0.88766000, '0101000020E61000009DF4BEF1B567ECBF064B75012FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27204752859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27204752859.webp', 'https://www.flickr.com/photos/zaragozaantigua/27204752859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25520, 'Puerta del Carmen aâ”œâ–’os 30', 'Vista de la Puerta del Carmen desde la confluencia del paseo Marâ”œآ،a Agustâ”œآ،n con la calle de Hernâ”œأ­n Cortâ”œآ®s, en un entorno en obras. Al fondo, la arbolada calle del General Sanjurjo. En la extrema derecha, el colegio de la Compaâ”œâ–’â”œآ،a de Marâ”œآ،a. Fuente visual: Heraldo.es', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.64985300, -0.88777200, '0101000020E610000090BE49D3A068ECBF8F1A13622ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32950291361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32950291361.webp', 'https://www.flickr.com/photos/zaragozaantigua/32950291361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25523, 'Puerta del Carmen 1922', 'Dibujo de Dâ”œآ،az Domâ”œآ،nguez que muestra la Puerta del Carmen en 1922, con un carro atravesâ”œأ­ndola procedente de la ciudad. Fuente: Revista La Cadiera.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64983200, -0.88770300, '0101000020E61000006FF4311F1068ECBF78F2E9B12DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43142601042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43142601042.webp', 'https://www.flickr.com/photos/zaragozaantigua/43142601042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25524, 'Zaragoza 1925', '"Anuncios econâ”œâ”‚micos. Cambio cuadro estilo futurista, por uno de Goya. Razâ”œâ”‚n, Ayuntamiento." Dibujo humorâ”œآ،stico de Luis Teixidor, "Teixi", en el diario "La voz de Aragâ”œâ”‚n". Hace referencia al urbanismo zaragozano de 1925, incluyendo alusiones al abastecimiento de aguas, a las expropiaciones, a la edificaciâ”œâ”‚n de la huerta de Santa Engracia, a la Casa de Socorro, al alumbrado supletorio, a la edificaciâ”œâ”‚n de las "Casas Baratas", al aislamiento de la Puerta del Carmen, a la nueva câ”œأ­rcel, al Mercado de Pescados, al puente del Gâ”œأ­llego, a los bancos anunciados, a la pavimentaciâ”œâ”‚n del paseo de la Independencia y al tranvâ”œآ،a a Casablanca. Cuestiones candentes en la â”œآ®poca, que quedan para siempre fijadas en un ingenioso collage.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64987200, -0.88763900, '0101000020E6100000BFEE74E78967ECBF064B75012FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50916237621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50916237621.webp', 'https://www.flickr.com/photos/zaragozaantigua/50916237621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25526, 'Puerta-del-Carmen c.1925', 'Inâ”œآ®dita imagen centrada en la Puerta del Carmen con una interesante vista tomada desde la glorieta entre el final del paseo de Pamplona y el principio del paseo de Marâ”œآ،a Agustâ”œآ،n. A la izquierda de la Puerta, tapias de la huerta del convento de la Encarnaciâ”œâ”‚n tras las que puede verse parcialmente la antigua iglesia y convento de ese nombre. Hacia el fondo, la arbolada calle de la Soberanâ”œآ،a Nacional. A la derecha, esquinero inmueble adosado a la Puerta y que albergaba el nâ”¬â•‘ 23 de esa calle (que albergaba la tienda de ultramarinos y comestibles de Agustâ”œآ،n Charles) y el nâ”¬â•‘ 4 del antiguo paseo de Ronda, en cuyos bajos destaca el toldo para atenuar la solanera del Cafâ”œآ® de Levante (asâ”œآ، llamado porque cuando se abriâ”œâ”‚ en 1895 aquâ”œآ، comenzaba la carretera de Valencia). Un ingreso a los lavaderos del Carmen se encontraba tras este inmueble, que poco despuâ”œآ®s fue expropiado por el Ayuntamiento para derribarlo y poder asâ”œآ، acometer el proyecto de aislamiento de la Puerta del Carmen.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64986700, -0.88766000, '0101000020E61000009DF4BEF1B567ECBFF4DF83D72ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53233164252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53233164252.webp', 'https://www.flickr.com/photos/zaragozaantigua/53233164252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26002, 'Vista aâ”œآ®rea Puerta del Carmen 1986', 'Foto: Josâ”œآ® Luis Pomarâ”œâ”‚n Vista aâ”œآ®rea del entorno de la Puerta del Carmen. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22128984860.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22128984860.webp', 'https://www.flickr.com/photos/zaragozaantigua/22128984860/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20919, 'Cruz del Coso 1766', 'Alzado de la Cruz del Coso, Cristâ”œâ”‚bal Estorguâ”œآ،a, Zaragoza, 1766. "Consta de una columna central con pedestal y zâ”œâ”‚calo, rematada con una cruz rodeada de 12 columnas que sostienen un segundo cuerpo de orden jâ”œâ”‚nico rematado con câ”œâ•‘pula y veleta; tanto el primer cuerpo como el segundo van rodeados de una verja". Versiâ”œâ”‚n de este monumento zaragozano erigido en la actual plaza de Espaâ”œâ–’a, en 1766. Antes y despuâ”œآ®s habâ”œآ،a tenido otras configuraciones, desde el siglo XV hasta 1808. Se trata de un humilladero cristiano que hace referencia a la leyenda de los Innumerables Mâ”œأ­rtires de Zaragoza. Fuente: Archivo General de Simancas, Ministerio de Cultura de Espaâ”œâ–’a.', 1766, 1766, 1766, 'Siglo XIX', 'CENTRO', 41.65238300, -0.88090200, '0101000020E610000049641F645930ECBFB2BB404981D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19790094814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19790094814.webp', 'https://www.flickr.com/photos/zaragozaantigua/19790094814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20929, '&quot;Casa de Pilatos&quot; 1500', '"Patio de la casa de Pilatos de Zaragoza". Dibujo de Valentâ”œآ،n Carderera y Solano, realizado en 1855, con la vista del patio interior de una desaparecida casona seâ”œâ–’orial sita en la esquina de la antigua plaza de San Gil con la calle del Horno del Hospitalico, cuando el acceso a esta iglesia parroquial se hacâ”œآ،a por esa plaza (en el siglo XVIII, a la iglesia de San Gil, como a otras, le cambiaron la orientaciâ”œâ”‚n de los pies y la cabecera). Las trazas estructurales y decorativas propias del tardo-gâ”œâ”‚tico podrâ”œآ،an aproximar su fâ”œأ­brica a finales del siglo XV. La singularidad de la denominaciâ”œâ”‚n ("Pilatos") serâ”œآ،a una peculiar conexiâ”œâ”‚n entre el supuesto prefecto de la provincia romana de Judea en el siglo I de la Era, y el fabuloso martiriologio cristiano del siglo IV en la cercana "Cruz del Coso". Cuando Carderera realizâ”œâ”‚ este dibujo, el palacio era propiedad de la marquesa de Vilueâ”œâ–’a de Carrillo, y se encontraba en la esquina entre la calle de la Lechuga, y la de la puerta Cinegia. Fuente visual: ceres.mcu.es/', 1500, 1500, 1500, 'Siglo XIX', 'CENTRO', 41.65280000, -0.88019400, '0101000020E61000006555849B8C2AECBF166A4DF38ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24700673350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24700673350.webp', 'https://www.flickr.com/photos/zaragozaantigua/24700673350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20957, 'Puerta Cinegia c.1800', '"Puerta Cineja", Antonio Callaved, 2011. Representaciâ”œâ”‚n idealizada de la Puerta Cinegia de Zaragoza, en la actual plaza de Espaâ”œâ–’a, a la entrada del Tubo. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1800, 1800, 1800, 'Siglo XIX', 'CENTRO', 41.65233500, -0.88054000, '0101000020E6100000213CDA38622DECBFA18499B67FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15275553211.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15275553211.webp', 'https://www.flickr.com/photos/zaragozaantigua/15275553211/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20965, 'Cruz del Coso 1826', 'Aguafuerte diseâ”œâ–’ado por Antonio Vicente y grabado por Josâ”œآ® Gabriel Lafuente, Zaragoza, 1826. Versiâ”œâ”‚n de este monumento zaragozano proyectado pero no realizado como aquâ”œآ، aparece, sino una versiâ”œâ”‚n mucho mâ”œأ­s sencilla erigida hasta 1835, cuando fue derribado. Antes habâ”œآ،a tenido otras configuraciones, desde el siglo XV hasta 1808. Se trata de un humilladero cristiano que hace referencia a la leyenda de los Innumerables Mâ”œأ­rtires de Zaragoza. Fuente: â”œأ¼lbum grâ”œأ­fico de Zaragoza, 1985.', 1826, 1826, 1826, 'Siglo XIX', 'CENTRO', 41.65238300, -0.88090200, '0101000020E610000049641F645930ECBFB2BB404981D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18870969913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18870969913.webp', 'https://www.flickr.com/photos/zaragozaantigua/18870969913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21045, 'Plaza de la Constituciâ”œâ”‚n 1860', 'Dibujo de la plaza de la Constituciâ”œâ”‚n con el fondo del salâ”œâ”‚n de paseo de Santa Engracia. Centra la plaza la neptuniana Fuente de la Princesa. A la derecha, el original edificio de la Diputaciâ”œâ”‚n provincial coronado por una enseâ”œâ–’a nacional de tamaâ”œâ–’o imposible hasta hace no demasiado tiempo. Los peatones y algâ”œâ•‘n carruaje transitan por un entorno que lamentablemente nunca tuvo los gruesos â”œأ­rboles que aquâ”œآ، figuran.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65216800, -0.88115900, '0101000020E61000001E6FF25B7432ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52299716137.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52299716137.webp', 'https://www.flickr.com/photos/zaragozaantigua/52299716137/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21117, 'Plaza de la Constituciâ”œâ”‚n c.1880', 'Espectacular imagen de la plaza de la Constituciâ”œâ”‚n, diâ”œأ­fana y aparentemente desierta por el dilatado tiempo de exposiciâ”œâ”‚n que requerâ”œآ،a consumar la captura fotogrâ”œأ­fica, de modo que apenas si aparecen localizados leves "rastros" o "sombras": una mâ”œآ،nima anâ”œآ®cdota. La foto, posiblemente, fue realizada desde altura en el palacio de la Diputaciâ”œâ”‚n Provincial. Domina el escenario de la plaza la provisoria fuente de Neptuno, que nos apunta directamente con su pâ”œآ®treo brazo. A la izquierda, edificios de la plaza, y del Coso, con el arranque de la calle de Don Jaime I. Entre esos edificios, inâ”œآ®dita imagen del antiguo nâ”¬â•‘ 47, casona que en sus bajos acogiâ”œâ”‚ la "Confiterâ”œآ،a del Arco de Cinegio", aquâ”œآ، "Pastelerâ”œآ،a de Bazâ”œأ­n". Unos aâ”œâ–’os mâ”œأ­s tarde serâ”œآ،a derribada la casa y, sobre ella se levantarâ”œآ،a un nuevo edificio ya de cuatro alturas, que no perdurarâ”œآ،a demasiado: en 1928, junto con su vecino de la derecha, formarâ”œأ­n el solar donde serâ”œأ­ construida una destacada central bancaria. Al fondo del Coso, soleado, el bloque del nâ”¬â•‘ 1 de la calle de Espartero. A la derecha, la que fuera antigua Fonda de Europa desde mediados de siglo, ya reformada y habilitada como "Gran Hotel de Europa", con el detalle de la peluquerâ”œآ،a que ocupaba su esquina. El suelo, parece todavâ”œآ،a sin el primer tendido tranviario de la ciudad, el que circulaba con propulsiâ”œâ”‚n de sangre. Fuente visual: Estudio Coyne, AHPZ-DARA', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26407211070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26407211070.webp', 'https://www.flickr.com/photos/zaragozaantigua/26407211070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21152, 'Pl. de la Constituciâ”œâ”‚n 1894', 'Imagen de la. plaza de la Constituciâ”œâ”‚n con la fachada de los edificios del Coso. La francesa escultura del "dios" de los mares sigue soberana en este espacio. Al fondo, la calle Mâ”œأ­rtires. A su derecha, andamios de construcciâ”œâ”‚n del gran edificio del Coso, actuales nâ”œâ•‘meros 43-45, segâ”œâ•‘n proyecto de Antonio Miranda. A sus pies, un tranvâ”œآ،a a propulsiâ”œâ”‚n de sangre, posiblemente o de la lâ”œآ،nea del Arrabal, o de la del Bajo Aragâ”œâ”‚n. Justo a su derecha, solar en construcciâ”œâ”‚n de los edificios que en 1928 serâ”œأ­n derribados para levantar encima la nueva sede del Banco Zaragozano. Fuente visual: Archivo familiar Gâ”œâ”‚mez Laguna, en "El libro de oro de Aragâ”œâ”‚n", EPA, 1997.', 1894, 1894, 1894, 'Siglo XIX', 'CENTRO', 41.65234300, -0.88072900, '0101000020E6100000EB707495EE2EECBF2463B5F97FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18756989534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18756989534.webp', 'https://www.flickr.com/photos/zaragozaantigua/18756989534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21300, 'Pl. de la Constituciâ”œâ”‚n 1903', 'Fotografâ”œآ،a centrada en el "Antiguo Monumento a los Mâ”œأ­rtires" (sic) ubicado en la plaza de la Constituciâ”œâ”‚n, que es el moderno a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y la Patria, sin el remate escultâ”œâ”‚rico escargado a Agustâ”œآ،n Querol y Subirats, culminado por un â”œأ­ngel victorioso, y sin la luminosa alegorâ”œآ،a femenina de Zaragoza. Con motivo de la visita a la ciudad del rey Alfonso XIII en octubre de ese aâ”œâ–’o, y para engalanar siquiera de forma efâ”œآ،mera lo que no era sino un â”œأ­rido pedestal coronado por la nada, cuya parte inferior parece un antecedente de la arquitectura brutalista, se colocâ”œâ”‚ la preciosa y monumental corona con lazo de la imagen, adornada con bombillas de colores. Una sublimaciâ”œâ”‚n de lo kitsch. Al fondo, antigua fachada edilicia del Coso, desde el nâ”¬â•‘ 29, antigua casa de Coloma, hasta el nâ”¬â•‘ 35. Transita un tranvâ”œآ،a "Primitivo" posiblemente en servicio en la lâ”œآ،nea 2. Madrid. Fuente visual: AMZ.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65223700, -0.88088000, '0101000020E6100000556AF6402B30ECBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32656919998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32656919998.webp', 'https://www.flickr.com/photos/zaragozaantigua/32656919998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21392, 'Pl. de la Constituciâ”œâ”‚n 1918', '"Trazo del Coso conocido como Brasero de los pobres". Foto: Julio Requejo, 8 de abril de 1918. Confluencia del Coso con la plaza de la Constituciâ”œâ”‚n de Zaragoza. Al fondo, entrada a la calle de Don Jaime I. La orientaciâ”œâ”‚n de las fachadas de este lugar hacia el sur propicia que su exposiciâ”œâ”‚n al sol resulte mâ”œأ­s câ”œأ­lida que en otras localizaciones. Fuente: DARA/AHPZ.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65220800, -0.88042900, '0101000020E610000045662E70792CECBF44183F8D7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21173092991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21173092991.webp', 'https://www.flickr.com/photos/zaragozaantigua/21173092991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21397, 'Pl. de la Constituciâ”œâ”‚n 1913', 'Luminosa imagen de la plaza de la Constituciâ”œâ”‚n capturada desde cerca del arranque de la calle de Don Jaime I, hacia donde se dirigen un par de carros tirados por caballerâ”œآ،as, en primer tâ”œآ®rmino, junto a un seâ”œâ–’or con una pata de palo. Tras ellos, un tranvâ”œآ،a "Jardinera-motora", posiblemente de la serie 25-28, en la terminal de la lâ”œآ،nea de Torrero y encaminado hacia el ascenso hasta la playa de Torrero. El fondo edilicio de la plaza aparece centrado por la decimonâ”œâ”‚nica fachada de la Diputaciâ”œâ”‚n Provincial, flanqueada por los inmuebles del nâ”¬â•‘ 1, a la derecha, y el nâ”¬â•‘ 3, a la izquierda, esquinero con el paseo de la Independencia, que poco despuâ”œآ®s serâ”œأ­ derribado y sustituido por uno nuevo como sede del Banco Hispano Americano. En los bajos de este edificio estaba desde 1858 el Cafâ”œآ® Suizo, desaparecido tras el derribo del inmueble.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65219100, -0.88102000, '0101000020E6100000C5E6E3DA5031ECBF6EDFA3FE7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21470799895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21470799895.webp', 'https://www.flickr.com/photos/zaragozaantigua/21470799895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23156, 'Calle Adolfo Suâ”œأ­rez 2007', 'Aspecto de la reciâ”œآ®n denominada calle de Adolfo Suâ”œأ­rez, en el barrio rural de la Venta del Olivar. Este camino rural sin asfaltar, antes sin nombre, serâ”œأ­ despuâ”œآ®s urbanizado. Al fondo, camino de Pinseque. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', NULL, 41.67706700, -0.96810700, '0101000020E6100000E2EA0088BBFAEEBFB519A721AAD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32390264582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32390264582.webp', 'https://www.flickr.com/photos/zaragozaantigua/32390264582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21414, 'Pl. de la Constituciâ”œâ”‚n c.1912', 'Desde uno de los balcones del decimonâ”œâ”‚nico "Gran Hotel de Europa", una imagen desde cierta altura de la antigua plaza de la Constituciâ”œâ”‚n, y el emboque en ella del Coso alto. Al fondo, la que fuera "Casa de Juan Coloma" del XVI, luego palacio de los duques de Hâ”œآ،jar, ya habâ”œآ،a sido convertida en el elegante y modernista Casino Mercantil y Agrâ”œآ،cola, adaptado por Francisco Albiâ”œâ–’ana. A la izquierda, "La Joyita" (joyerâ”œآ،a) y la "Murga" (bombonerâ”œآ،a), ademâ”œأ­s de la cafeterâ”œآ،a "Gambrinus", en los bajos del edificio esquinero. A la derecha, otro seâ”œâ–’ero establecimiento: el "Gran Cafâ”œآ® Royalty", y el acceso a la calle de los Mâ”œأ­rtires. Los tranvâ”œآ،as traquetean como elâ”œآ®ctricos girâ”œâ”‚vagos para circunvalar la plaza, o bien para continuar por el Coso. Los toldos atenâ”œâ•‘an la severa solanera. Posiblemente, se trata de una postal editada y comercializada por la casa parisina "Levy Fils et Cie". Fuente: www.ebay.es/', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65243100, -0.88095600, '0101000020E610000015E126A3CA30ECBFC3F2E7DB82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28482008524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28482008524.webp', 'https://www.flickr.com/photos/zaragozaantigua/28482008524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21423, 'MIguel Faci Abad 1912', 'Imagen de Miguel Faci Abad, joyero, fotâ”œâ”‚grafo aficionado, y amante de la fotografâ”œآ،a, autor de un prestigioso archivo (junto con su hermano Gabriel, que le da nombre) que contiene una mâ”œأ­s que interesante colecciâ”œâ”‚n de imâ”œأ­genes de la ciudad de los aâ”œâ–’os veinte y treinta del pasado siglo. La captura ha sido realizada en el "Art-Studio Gustavo Freudenthal", en su original ubicaciâ”œâ”‚n de la calle Coso nâ”¬â•‘ 31. Fuente visual: archivo fotogrâ”œأ­fico Gabriel Faci, AHPZ.', 1912, 1912, 1912, 'Anos 10', 'CENTRO', 41.65266700, -0.88108300, '0101000020E61000005DF8C1F9D431ECBFD7169E978AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31725996393.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31725996393.webp', 'https://www.flickr.com/photos/zaragozaantigua/31725996393/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21431, 'Pl. de la Constituciâ”œâ”‚n c.1918', 'Bulliciosa imagen de la plaza de la Constituciâ”œâ”‚n capturada posiblemente desde la altura del Hotel Europa, y centrada en la luminosa fachada del Coso recayente a la plaza. Al fondo, sobresale la torre de San Pablo Apâ”œâ”‚stol. Donde estuviera la antigua Casa de Coloma destaca el airoso remate en forma de palomar del reciente Centro Mercantil, Industrial y Agrâ”œآ،cola. Aunque el sol no es aâ”œâ•‘n el aplastante martillo canicular, muchos toldos del Coso estâ”œأ­n ya tendidos, como el del reciente Gran Cafâ”œآ® Royalty (nâ”¬â•‘ 35), y el del algo mâ”œأ­s veterano Gran Cafâ”œآ® Oriental (nâ”¬â•‘ 39), esquinero con la calle de los Mâ”œأ­rtires. A la izquierda del Royalty, sin toldos, la prestigiosa Joyerâ”œآ،a Agâ”œâ•‌eras (nâ”¬â•‘ 33). En primer plano, una unidad tranviaria de la serie Primitivos de la lâ”œآ،nea del Bajo Aragâ”œâ”‚n, y una composiciâ”œâ”‚n de jardineras (motor+dos remolques) de la lâ”œآ،nea que sube a la Playa de Torrero. Fuente visual: editorial Alberto Martâ”œآ،n (Barcelona)/colecciâ”œâ”‚n El Turismo Prâ”œأ­ctico, en Zaragoza estereoscâ”œâ”‚pica, fotografâ”œآ،a profesional y comercial 1850-1970, PUZ.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65217000, -0.88071800, '0101000020E6100000F1F3DF83D72EECBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34947191205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34947191205.webp', 'https://www.flickr.com/photos/zaragozaantigua/34947191205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21729, 'El Tâ”œآ،o Rana 1933', 'El Tâ”œآ،o Rana era un ansotano de gran envergadura que visitaba con frecuencia Zaragoza en los aâ”œâ–’os 20 y 30, vestido con el traje tâ”œآ،pico de su tierra. Tenâ”œآ،a mucho dinero procedente del ganado y la madera. Protagonizâ”œâ”‚ varias anâ”œآ®cdotas, relacionadas con el rechazo a su indumentaria. Al ser advertido en un hotel de lujo que â”œآ®ste estaba por encima de sus posibilidades, esgrimiâ”œâ”‚ un fajo de billetes y requiriâ”œâ”‚ comprar el edificio entero. Por la misma razâ”œâ”‚n, adquirâ”œآ،a dos localidades en el teatro Principal: una para â”œآ®l y otra para su sombrero. Se dice que en una ocasiâ”œâ”‚n, una compaâ”œâ–’â”œآ،a de zarzuela actuâ”œâ”‚ sâ”œâ”‚lo para â”œآ®l, al haber comprado todas las entradas. Tambiâ”œآ®n se cuenta que los potentados de la ciudad no pudieron utilizar los coches de caballos de alquiler a la salida de una corrida en la plaza de toros, puesto que â”œآ®l habâ”œآ،a pagado a todos para que circularan alrededor. Las incomprobables historias, que incluyen posibles descendientes no reconocidos y el uso de billetes para encenderse los puros por el paseo de la Independencia, son innumerables, como los mâ”œأ­rtires de Zaragoza. Lo vemos donde solâ”œآ،a sentarse: en el velador del cafâ”œآ® Royalty, en la plaza de la Constituciâ”œâ”‚n con acceso por la calle Mâ”œأ­rtires. El comercio de la derecha es la casa de vinos de Miguel Mur, con el portal del entonces nâ”œâ•‘mero 37 del Coso, anunciando al procurador Luis Villoro. Fuente visual: foto Gonzalo Reparaz Ruiz., en Institut Cartogrâ”œأ،fic i Geolâ”œâ–“gic de Catalunya.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65232700, -0.88070900, '0101000020E6100000245F09A4C42EECBF1EA67D737FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21147570606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21147570606.webp', 'https://www.flickr.com/photos/zaragozaantigua/21147570606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21774, 'Pl. de la Constituciâ”œâ”‚n 1930', 'Plaza de la Constituciâ”œâ”‚n y Coso Alto, con perspectiva hasta la calle de las Escuelas Pâ”œآ،as, al fondo. A la derecha, el Gran Cafâ”œآ® Royalty y la Joyerâ”œآ،a Agâ”œâ•‌eras. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65258200, -0.88105300, '0101000020E6100000B35DA10F9631ECBFA9FA95CE87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22879936329.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22879936329.webp', 'https://www.flickr.com/photos/zaragozaantigua/22879936329/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21836, 'Jacques Doriot 1938', 'Imagen con motivo de la visita de Jacques Doriot, jefe del Partido Popular Francâ”œآ®s (PPF), sentado, en el centro, durante una veraniega gira de apoyo y respaldo por parte de este partido de la derecha extrema y fascista francesa, a la Espaâ”œâ–’a nacionalista en localidades como Irâ”œâ•‘n, San Sebastiâ”œأ­n, Bilbao, Santander, Burgos, Sevilla, Zaragoza... La captura se ha realizado posiblemente en la sede provincial de Falange Espaâ”œâ–’ola Tradicionalista, y detrâ”œأ­s de Doriot figura Jesâ”œâ•‘s Muro Sevilla, Jefe provincial de FET, ademâ”œأ­s de otros jerarcas locales. Junto a Doriot, Claude Popelin, miembro del Bureau Politique del PPF y su responsable de propaganda. Colaboracionista con la ocupaciâ”œâ”‚n alemana de Francia en 1940, en julio de 1941 Doriot impulsarâ”œأ­ activamente (junto con otros partidos de la derecha extrema francesa) la creaciâ”œâ”‚n de la Lâ”œآ®gion des volontaires franâ”œآ؛ais (contre le bolchâ”œآ®visme) o LVF, que participarâ”œأ­ en la agresiâ”œâ”‚n militar de la Alemania nazi contra la URSS. Fuente visual: revista "Vida Aragonesa, III Aâ”œâ–’o Triunfal".', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34196737331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34196737331.webp', 'https://www.flickr.com/photos/zaragozaantigua/34196737331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21874, 'Pl. de la Constituciâ”œâ”‚n c.1935', 'Imagen centrada en el monumento a los dieciocho (recontados oficialmente como "innnumerables") mâ”œأ­rtires de Zaragoza sito en la plaza de la Constituciâ”œâ”‚n. Al fondo, principio del paseo de la Independencia. A la derecha, el edificio del antiguo banco Hispano Americano. Fuente visual: www.todocoleccion.net', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65218700, -0.88118000, '0101000020E6100000FB743C66A032ECBF2CF015DD7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39946725911.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39946725911.webp', 'https://www.flickr.com/photos/zaragozaantigua/39946725911/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21922, 'Plaza de la Constituciâ”œâ”‚n 1936', 'Imagen capturada el 27 de julio de 1936, una semana despuâ”œآ®s del golpe de Estado contra la legalidad republicana y centrada en un retâ”œآ®n de la organizaciâ”œâ”‚n parapolicial Acciâ”œâ”‚n Ciudadana. La ubicaciâ”œâ”‚n de la fotografâ”œآ،a, plaza de la Constituciâ”œâ”‚n en la acera del Coso a la altura del emboque a la calle de los Mâ”œأ­rtires, responde a la estratâ”œآ®gica importancia de esta plaza para asegurar el control de la ciudad, donde aparte de la inmediata presencia de la Diputaciâ”œâ”‚n Provincial, contarâ”œآ،a en sus inmediaciones con el centro de detenciâ”œâ”‚n establecido en el Bazar X, ademâ”œأ­s de la destacada y cercana presencia de los locales de Izquierda Republicana y la Casa del Pueblo (calle de los Estâ”œآ®banes), Uniâ”œâ”‚n Republicana (calle del Cuatro de Agosto) y del ramo de Telâ”œآ®fonos de la Federaciâ”œâ”‚n Local de Sindicatos â”œأœnicos (en esa misma calle). Acciâ”œâ”‚n Ciudadana encuadraba a elementos civiles afines al golpe de Estado, organizados bajo las â”œâ”‚rdenes de oficiales del Ejâ”œآ®rcito afectados por las reformas militares de Manuel Azaâ”œâ–’a. Su gâ”œآ®nesis arranca en Zaragoza ya en 1934 con la organizaciâ”œâ”‚n clandestina de voluntarios civiles contrarios al proyecto republicano en una estructura paramilitar con funciones parapoliciales encuadrada, armada y con experiencia en contrarrestar los conflictos sociales de los aâ”œâ–’os previos al golpe. Esta gâ”œآ®nesis demuestra (una vez mâ”œأ­s) que el recorrido de los preparativos de este golpe venâ”œآ،an desde tiempo atrâ”œأ­s, comenzando en tâ”œآ®rminos generales en 1931 con la llegada pacâ”œآ،fica de la Repâ”œâ•‘blica y acelerâ”œأ­ndose de forma irremediable tras la amarga noche en que las elecciones de febrero de 1936 negaron democrâ”œأ­ticamente el triunfo a las fuerzas conspirativas. Los voluntarios de la imagen posan ante una camioneta de la fâ”œأ­brica mecâ”œأ­nica de cajas de cartâ”œâ”‚n de Luis Garcâ”œآ،a Gil sita en la calle de las Minas, y es posible que aquâ”œآ، figure el propio Luis Garcâ”œآ،a Gil y su hermano Ramâ”œâ”‚n. Tras la guerra, Luis fue miembro destacado de las nuevas estructuras de organizaciâ”œâ”‚n local de la industria del c', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65232000, -0.88076200, '0101000020E6100000DAE731CA332FECBF6C43C5387FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54907595080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54907595080.webp', 'https://www.flickr.com/photos/zaragozaantigua/54907595080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21972, 'Plaza de Espaâ”œâ–’a 1941', '"Zaragoza. Plaza de Espaâ”œâ–’a. Noche de nieve". Foto Luker. Nocturna imagen (convertida en postal) de un invierno ocasionalmente mâ”œأ­s fresco que de ordinario, con precipitaciâ”œâ”‚n en forma de nieve incluida. El fenomenal y natural bucolismo escâ”œآ®nico parece no ser muy apreciado por los indâ”œآ،genas, tal vez al abrigo de sus hogares. Los despejados raâ”œآ،les tranviarios, y algunas huellas de pisadas, â”œâ•‘nicos rastros de trâ”œأ­nsito ciudadano. Fuente visual: www.delcampe.net/', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23826303046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23826303046.webp', 'https://www.flickr.com/photos/zaragozaantigua/23826303046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22011, 'Pl. de Espaâ”œâ–’a 1944', 'La plaza de Espaâ”œâ–’a desde la altura del edificio del nâ”¬â•‘ 1, esquinero con el Coso Medio. En el centro, la arbolada isleta que circunvalaba el monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y de la Patria con el aspecto conferido en la reciente reforma de 1942. Tras ella, los tres referenciales inmuebles del este de la plaza: el Banco Zaragozano, el Banco de Espaâ”œâ–’a y la Sociedad de Seguros La Catalana. Al fondo, el Coso Medio. A la derecha, el arranque del paseo de la Independencia. Fuente visual: Ediciones Arribas, en www.delcampe.net/', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.65218700, -0.88118000, '0101000020E6100000FB743C66A032ECBF2CF015DD7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42181909880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42181909880.webp', 'https://www.flickr.com/photos/zaragozaantigua/42181909880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22015, 'Plaza de Espaâ”œâ–’a c.1941', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 37 del Coso y centrada en latradiconal escena formada por la vista de la ya redenominada plaza de Espaâ”œâ–’a y el arranque del bulevar del paseo de la Independencia. A la derecha, esquinera y antigua sede central del Banco Hispano Americano, poco antes de su remodelaciâ”œâ”‚n integral. A continuaciâ”œâ”‚n, el moderno y algo mâ”œأ­s vertical inmueble del nâ”¬â•‘ 4 del paseo de la Independencia.', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.65234400, -0.88085800, '0101000020E61000006170CD1DFD2FECBFF4DE180280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49239946827.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49239946827.webp', 'https://www.flickr.com/photos/zaragozaantigua/49239946827/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22174, 'Pl. de Espaâ”œâ–’a 1954', 'Imagen del apoteâ”œâ”‚sico desfile celebrado el dâ”œآ،a 12 de octubre con motivo del Congreso Nacional Mariano, y que consistiâ”œâ”‚ en una procesionaria compuesta por 27 imâ”œأ­genes de la Virgen, en representaciâ”œâ”‚n de las provincias peninsulares, desde la sedente imagen del Inmaculado Corazâ”œâ”‚n de Marâ”œآ،a, hasta la montaraz Virgen de Covadonga. En la fotografâ”œآ،a, capturada desde el balcâ”œâ”‚n del reciente edificio de la Diputaciâ”œâ”‚n Provincial, uno de los pasos del desfile, atentamente seguido por el Caudillo y Jefe del Estado, Francisco Franco, y su esposa, Carmen Polo. Fuente visual: AMZ.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65229400, -0.88113900, '0101000020E6100000575D876A4A32ECBF42B0AA5E7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31478749752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31478749752.webp', 'https://www.flickr.com/photos/zaragozaantigua/31478749752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22268, 'El Tubo c.1963', 'Archivo fotogrâ”œأ­fico del diario ABC. Cedida por Rafael Castillejo. El barrio del Tubo de Zaragoza se extiende por el lado sur del antiguo perâ”œآ،metro romano, con entrada por plaza de Espaâ”œâ–’a. En la imagen del final de la calle Mâ”œأ­rtires en su confluencia, al fondo, con la calle Cuatro de Agosto: el Plata, Casa Lac, el Salâ”œâ”‚n Limpiabotas y el letrero indicador del Restaurante Teâ”œâ”‚filo. Mâ”œأ­s informaciâ”œâ”‚n sobre este rincâ”œâ”‚n de Zaragoza, aquâ”œآ،: sites.google.com/site/tausiet/eltubo', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65248500, -0.88038200, '0101000020E610000018963FDF162CECBFB610E4A084D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856817971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856817971.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856817971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22326, 'Plaza de Espaâ”œâ–’a c.1960', 'Imagen de la plaza de Espaâ”œâ–’a en su enlace con el Coso Medio, capturada desde el emboque a la calle Mâ”œأ­rtires. En primer tâ”œآ®rmino, el coche 52 de la lâ”œآ،nea 5 "Torrero". A la derecha, el Banco de Espaâ”œâ–’a. A la izquierda, el Zaragozano. Fuente visual: Diego Navarro Bonilla, amablemente aportada por Rafael Castillejo.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65220800, -0.88042900, '0101000020E610000045662E70792CECBF44183F8D7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16872143796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16872143796.webp', 'https://www.flickr.com/photos/zaragozaantigua/16872143796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22545, 'Serafina y El Plata c.1977', 'Foto Antonio Calvo Pedrâ”œâ”‚s. Puerta de entrada ("Bar") al cafâ”œآ® cantante El Plata de Zaragoza. Apostada a su vera, la cigarrera del Tubo, conocida como "Serafina", de nombre Herminia Martâ”œآ،nez Lines.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65280300, -0.88008900, '0101000020E610000011381268B029ECBF87DD770C8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14968429902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14968429902.webp', 'https://www.flickr.com/photos/zaragozaantigua/14968429902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22583, 'Calle Don Jaime I, 1973', 'Câ”œآ®sar Sâ”œأ­nchez Vâ”œأ­zquez. 1973. Imagen de la fachada de la veterana confiterâ”œآ،a "Sucesor de Aurâ”œآ،a", en la calle Don Jaime I, 9. Abierta en los albores del siglo XX, cerrâ”œâ”‚ definitivamente en 1982. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/792846500...', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65228300, -0.87968900, '0101000020E610000089D4B48B6926ECBF4E5E64027ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15600539992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15600539992.webp', 'https://www.flickr.com/photos/zaragozaantigua/15600539992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22674, 'Calle Mâ”œأ­rtires c.1972', 'Foto: Coyne. Procesiâ”œâ”‚n de Semana Santa en el tramo del Coso de la plaza de Espaâ”œâ–’a, con la calle de los Mâ”œأ­rtires al fondo a la derecha. En la esquina (Coso 39), la cafeterâ”œآ،a Las Vegas 2, donde permaneciâ”œâ”‚ el cafâ”œآ® Oriental durante seis dâ”œآ®cadas. Fuente: www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65241500, -0.88061300, '0101000020E61000009DD66D50FB2DECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24306663906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24306663906.webp', 'https://www.flickr.com/photos/zaragozaantigua/24306663906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22682, 'El Tubo c.1979', 'Vista de la calle de los Mâ”œأ­rtires en El Tubo. A la espalda del fotâ”œâ”‚grafo, la plaza de Espaâ”œâ–’a. Fuente: "Zaragoza", Editorial Everest, 1980.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65250300, -0.88048400, '0101000020E610000028D714C8EC2CECBF5DC5E23785D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26592920796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26592920796.webp', 'https://www.flickr.com/photos/zaragozaantigua/26592920796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22930, 'Pl. de Espaâ”œâ–’a 1981', 'El ruido de sables cobrâ”œâ”‚ forma la tarde del lunes 23 de febrero cuando un grupo de guardiaciviles irrumpiendo en la sesiâ”œâ”‚n plenaria del Congreso de los Diputados. En la imagen, numerosas personas se concentran durante la maâ”œâ–’ana del 24 de febrero en la plaza de Espaâ”œâ–’a, junto a la entrada de la calle de los Mâ”œأ­rtires (izquierda), esperando la resoluciâ”œâ”‚n del fracasado golpe de Estado. A las 10:00 fueron liberados los diputados retenidos en el Congreso, y a las 12:15 todo habâ”œآ،a terminado. El viernes 27 de febrero se celebrâ”œâ”‚ en Zaragoza una manifestaciâ”œâ”‚n de repulsa del golpismo convocada por los partidos polâ”œآ،ticos y centrales sindicales mayoritarias, con el lema Por la libertad, la democracia y la Constituciâ”œâ”‚n, entre las plaza de Paraâ”œآ،so y de San Francisco. Al dâ”œآ،a siguiente el Jefe del Estado visitâ”œâ”‚ la Academia General Militar, donde se escenificâ”œâ”‚ la tensiâ”œâ”‚n del momento en el tono de los discursos dados. Fuente: Colecciâ”œâ”‚n Antonio Tausiet.', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65233300, -0.88059200, '0101000020E6100000C0D02346CF2DECBF008DD2A57FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31081371963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31081371963.webp', 'https://www.flickr.com/photos/zaragozaantigua/31081371963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22950, 'Plaza de Espaâ”œâ–’a c.1981', 'Imagen centrada en el vistoso escaparate de la veterana Joyerâ”œآ،a Agâ”œâ•‌eras en su establecimiento ubicado en el Coso nâ”¬â•‘ 33, adonde fue a parar ya comenzado el siglo XX desde su fundaciâ”œâ”‚n originaria en la calle de Estâ”œآ®banes en el aâ”œâ–’o 1870. La joyerâ”œآ،a perdura hoy en una moderna tienda con taller propio sita en la calle de la Torre Nueva, mientras el local de la imagen ha sido engullido por el esquinero gigante de los frutos secos. La traza decorativa del comercio fue luego eliminada durante una posterior restauraciâ”œâ”‚n integral del inmueble. Fuente visual: joyeriaagueras.es', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40188654935.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40188654935.webp', 'https://www.flickr.com/photos/zaragozaantigua/40188654935/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22953, 'Calle de la Libertad c.1987', 'Imagen centrada en el inmueble del nâ”œâ•‘mero 16 de la calle de la Libertad, esquinero con la calle de los Estâ”œآ®banes (a la derecha), una antigua casa de arquitectura tradicional remodelada en profundidad en la segunda mitad del siglo XIX dentro de la entonces imperante estâ”œآ®tica academicista. Aâ”œâ–’os mâ”œأ­s tarde, el edificio serâ”œآ،a derribado y sustituido por uno nuevo que mantuvo la altura, las formas y la distribuciâ”œâ”‚n de vanos. Al fondo de la calle, solar del antiguo nâ”¬â•‘ 14 de la calle de Mâ”œآ®ndez Nâ”œâ•‘â”œâ–’ez en cuyos bajos se ubicâ”œâ”‚ una parte del gran establecimiento comercial de la empresa "Muebles y Camas Metâ”œأ­licas Viuda de S. Irisarri", frente a la singular plazuela de la Cabra (referencia a la antigua familia Lacabra). Fuente visual: AMZ.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65359700, -0.88008500, '0101000020E6100000B6679604A829ECBFC1E10511A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42588933695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42588933695.webp', 'https://www.flickr.com/photos/zaragozaantigua/42588933695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23019, 'Coso Alto 1992', 'Imagen parcial del veterano edificio del nâ”¬â•‘ 33 del Coso, interesante muestra de la arquitectura eclecticista-academicista de los aâ”œâ–’os 70 del siglo XIX en lo que fuera casa de los marqueses de Nibbiano y barones de Arayzaga. Sobre el gran portâ”œâ”‚n del ingreso principal se conservaba la identificaciâ”œâ”‚n como propiedad del Banco Vitalicio de Espaâ”œâ–’a. En el centro de la imagen, el que fuera durante varias dâ”œآ®cadas establecimiento comercial de la destacada joyerâ”œآ،a Agâ”œâ•‌eras. En la parte superior de la imagen aparecen los primeros andamios de obra durante la restauraciâ”œâ”‚n integral del inmueble que, aâ”œâ–’adiendo una altura, lo acondicionarâ”œآ،a como moderno espacio de oficinas integrado en la nueva fachada del Coso a la plaza de Espaâ”œâ–’a. Fuente visual: AMZ.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41603118772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41603118772.webp', 'https://www.flickr.com/photos/zaragozaantigua/41603118772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23023, 'Calle de los Mâ”œأ­rtires 1997', 'Imagen del antiguo "Tubo" de la ciudad, en este caso una vista parcial de la calle de los Mâ”œأ­rtires con el fondo de su desemboque en la calle del Cuatro de Agosto. Esta captura visual muestra algunos de sus referentes establecimientos de restauraciâ”œâ”‚n, comercios y tenderetes antropolâ”œâ”‚gicos que singularizaban este desaparecido entorno provinciano de la Zaragoza que fue, y ya no es. Y todo a pocos segundos de la plaza de Espaâ”œâ–’a.', 1997, 1997, 1997, 'Anos 90', 'CENTRO', 41.65266500, -0.88027900, '0101000020E6100000F2608BDD3E2BECBF361FD7868AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50015671617.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50015671617.webp', 'https://www.flickr.com/photos/zaragozaantigua/50015671617/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23027, 'Calle de los Mâ”œأ­rtires 1992', 'Crepuscular imagen del tradicional "Tubo" centrada en la seâ”œâ–’era calle de los Mâ”œأ­rtires capturada desde su emboque por la plaza de Espaâ”œâ–’a, y hasta su cruce al fondo con la calle del Cuatro de Agosto. Aunque esta escena asemeja a tantas y tantas escenas anteriores de este singular espacio de la antigua ciudad, hay indicios en ella de que su tiempo estâ”œأ­ llegando a su final, como indican por ejemplo los carteles del lado de los impares de esta calle que avisan de "liquidaciâ”œâ”‚n" o "descuento por cese de negocio". La razâ”œâ”‚n: el proyecto residencial y comercial "Puerta Cinegia".', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65252100, -0.88045100, '0101000020E610000039605793A72CECBF037AE1CE85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50204635811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50204635811.webp', 'https://www.flickr.com/photos/zaragozaantigua/50204635811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23108, 'Calle Cuatro de Agosto 2003', 'Aspecto del rodaje del cortometraje "Casi Mallorca" (Miguel Manteca, 2003) en la calle del Cuatro de Agosto. A la izquierda, edificio de los nâ”œâ•‘meros 5 al 9 en rehabilitaciâ”œâ”‚n, con el acceso al Pasaje de los Giles.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65327300, -0.88105200, '0101000020E61000009C69C2F69331ECBF0E2E1D739ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24629327409.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24629327409.webp', 'https://www.flickr.com/photos/zaragozaantigua/24629327409/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23111, 'Calle Mâ”œأ­rtires 2003', 'Aspecto de la puerta de acceso al restaurante Casa Lac, el dâ”œآ،a de su cierre provisional, 1 de agosto de 2003, en el marco de la lucrativa reconversiâ”œâ”‚n del Tubo mediante el abandono durante aâ”œâ–’os. Su publicidad aseguraba que era "el restaurante mâ”œأ­s antiguo de Espaâ”œâ–’a", por haber sido abierto en 1825, con pastelerâ”œآ،a en los bajos y comedor isabelino en el primer piso. Su bar modernista fue realizado por Manuel Martâ”œآ،nez de Ubago en 1925, con escalera de Averly. En 2008 se rehabilitâ”œâ”‚ y volviâ”œâ”‚ a abrir sus puertas de la calle de los Mâ”œأ­rtires 12.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65280800, -0.88014100, '0101000020E6100000AFCC5B751D2AECBF994869368FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24878519582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24878519582.webp', 'https://www.flickr.com/photos/zaragozaantigua/24878519582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23115, 'Pl. de Espaâ”œâ–’a 2009', 'Imagen de la plaza de Espaâ”œâ–’a en los tiempos que era una rotonda automovilâ”œآ،stica. Al fondo, a la izquierda, el fino emboque a la calle de los Mâ”œأ­rtires, y los andamios de obra del edificio del nâ”¬â•‘ 2 de esa calle, integrado visualmente en el vanguardista proyecto "Puerta Cinegia", uno de los caracterâ”œآ،sticos ejemplos del urbanismo zaragozano del amontonamiento, que a unos encanta, y a otros, no tanto, y que en esta zona hay tantos y tan abundantes ejemplos. Fuente visual: www.flickr.com', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.65227400, -0.88048200, '0101000020E6100000FAEE5696E82CECBFFB03E5B67DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31003593290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31003593290.webp', 'https://www.flickr.com/photos/zaragozaantigua/31003593290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23119, 'Calle Estâ”œآ®banes 2006', 'En mayo de 2006, el derribo de las tapias de los nâ”œâ•‘meros 11 al 15 de la calle de los Estâ”œآ®banes mostrâ”œâ”‚ un aspecto novedoso del lugar. Este solar, de 250 metros cuadrados, fue objeto de una instalaciâ”œâ”‚n artâ”œآ،stica en el marco del programa cultural municipal "En la frontera". Despuâ”œآ®s, los negocios hosteleros vecinos fueron acondicionando allâ”œآ، sus terrazas. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65333500, -0.87973400, '0101000020E610000088BCE5EAC726ECBF842A357BA0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31106202764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31106202764.webp', 'https://www.flickr.com/photos/zaragozaantigua/31106202764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23272, 'Puerta Cinegia 1808', '"Hallâ”œأ­ndose un obâ”œâ•‘s atravesado en la calle del Coso por donde mâ”œأ­s vivos cruzaban los fuegos de una y otra parte, en lo mâ”œأ­s encendido del combate se arrojaron a tomarle el intrâ”œآ®pido D. Josâ”œآ® Fandos y un patriota catalâ”œأ­n, el cual muriâ”œâ”‚ gloriosamente en la acciâ”œâ”‚n, pero logrado su valeroso intento". Serie Ruinas de Zaragoza, de Juan Gâ”œأ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œأ­diz, 1812. Al fondo a la derecha, entre el humo, se ve la Puerta Cinegia, en la entrada del actual Tubo de la plaza de Espaâ”œâ–’a. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65234300, -0.88072900, '0101000020E6100000EB707495EE2EECBF2463B5F97FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15267348332.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15267348332.webp', 'https://www.flickr.com/photos/zaragozaantigua/15267348332/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23603, 'Pl. de la Constituciâ”œâ”‚n 1900', 'Plaza de la Constituciâ”œâ”‚n, con una notable confluencia de lâ”œآ،neas de tranvâ”œآ،a de tracciâ”œâ”‚n animal. En primer plano, los tranvâ”œآ،as de Torrero (el que agarra la curva hacia la derecha) y Circunvalaciâ”œâ”‚n (el que emboca el Coso). Al fondo, el tranvâ”œآ،a del Arrabal (gira hacia la calle Don Jaime), y el de Bajo Aragâ”œâ”‚n-Madrid. 4 lâ”œآ،neas de tranvâ”œآ،a pasando por la Plaza, y tan ricamente. El comercio, boyante; los peatones, tranquilos; la ciudad, "no problemo". Neptuno perduraba tridentino, aunque mal mirado y peor considerado por la intelectualidad catâ”œâ”‚lica local, a la que se la llevaban los demonios y requerâ”œآ،a quitarlo y sustituirlo por otro mito: el de los mâ”œأ­rtires cristianos sin nâ”œâ•‘mero. Pocos aâ”œâ–’os despuâ”œآ®s, asâ”œآ، se harâ”œآ،a.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65237600, -0.88106200, '0101000020E610000080F277EFA831ECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822836179.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822836179.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822836179/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23616, 'Plaza de Espaâ”œâ–’a 1943', '7 de mayo de 1943. Repatriados de la Divisiâ”œâ”‚n Azul desfilan por la plaza de Espaâ”œâ–’a camino del Pilar. Esta unidad de infanterâ”œآ،a formâ”œâ”‚ parte del ejâ”œآ®rcito nazi en su agresiâ”œâ”‚n armada contra la Uniâ”œâ”‚n Soviâ”œآ®tica. A la izquierda, la entrada de la calle Mâ”œأ­rtires. A la derecha, el remate del edificio de la Asociaciâ”œâ”‚n de Labradores en el Coso Medio. Fuente Archivo ABC.', 1943, 1943, 1943, 'Anos 40', 'CENTRO', 41.65220800, -0.88042900, '0101000020E610000045662E70792CECBF44183F8D7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20304208583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20304208583.webp', 'https://www.flickr.com/photos/zaragozaantigua/20304208583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23976, 'Plaza de Espaâ”œâ–’a 1974', 'Archivo Municipal Zaragoza. Josâ”œآ® Jaria Serrano. Mayo 1974. Con motivo de las "Fiestas de Primavera" y el "Coso Blanco", alegre desfile de la banda de mâ”œâ•‘sica de la Policâ”œآ،a Armada, por la Plaza de Espaâ”œâ–’a. Al fondo, a la derecha, la Câ”œأ­mara Oficial Provincial Agraria, y el comercio de mâ”œأ­quinas de coser Alfa. A la izquierda, territorio Omega: la Jefatura Provincial de Zaragoza de FET-JONS.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65268900, -0.88112700, '0101000020E610000046EC13403132ECBFBFBA2A508BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15239204581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15239204581.webp', 'https://www.flickr.com/photos/zaragozaantigua/15239204581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24017, 'El Plata 1987', 'Foto: Eduardo Bayona Estradera. Interior del cafâ”œآ® cantante El Plata, en la calle del Cuatro de Agosto 23. Fue cerrado en 1992 y reabierto en 2008. Fuente: eduardo-elmundoengeneral.blogspot.com', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65286200, -0.88016100, '0101000020E610000076DEC666472AECBF8C6665FB90D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24402393888.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24402393888.webp', 'https://www.flickr.com/photos/zaragozaantigua/24402393888/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24053, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Foto: Miguel Marâ”œآ،n Chivite. Manifestaciâ”œâ”‚n del 1 de mayo de 1931 en la plaza de la Constituciâ”œâ”‚n, con la embocadura del Coso Alto al fondo. A la derecha, pancarta de la Agrupaciâ”œâ”‚n Socialista de Zaragoza. Segâ”œâ•‘n la prensa de la â”œآ®poca, mâ”œأ­s de 30.000 personas se unieron a este evento, que tuvo carâ”œأ­cter mâ”œأ­s festivo que en anteriores convocatorias, debido al reciente advenimiento de la Segunda Repâ”œâ•‘blica. Fuente: Heraldo de Aragâ”œâ”‚n.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65231700, -0.88113900, '0101000020E6100000575D876A4A32ECBFFACF9A1F7FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31562681580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31562681580.webp', 'https://www.flickr.com/photos/zaragozaantigua/31562681580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24070, 'Pl. de la Constituciâ”œâ”‚n 1908', 'Imagen tomada durante la visita del rey Alfonso XIII a Zaragoza los dâ”œآ،as 14-15 de junio, junto con los infantes Don Fernando y Don Luis Alfonso (a la derecha), cuando formaban parte de la procesiâ”œâ”‚n "câ”œآ،vica" que acompaâ”œâ–’â”œâ”‚ los restos de Agustina Zaragoza, Manuela Sancho y Casta â”œأ¼lvarez desde el Pilar y hasta la iglesia del Portillo, donde fueron inhumadas. La captura se ha realizado, bajo lluvia, cuando la procesiâ”œâ”‚n estaba llegando a la plaza de la Constituciâ”œâ”‚n desde el Coso alto. Al fondo, tras el monarca y los infantes, los bajos del nâ”¬â•‘ 31 del Coso, remodelado como primera sede del Banco Hispano Americano, y tambiâ”œآ®n como estudio del fotâ”œâ”‚grafo Gustavo Freudenthal. A la izquierda, la antigua Casa de Coloma. Sobre el firme, tendido de la lâ”œآ،nea "Circunvalaciâ”œâ”‚n" del tranvâ”œآ،a. Fuente visual: foto Goâ”œâ–’i, en hemeroteca.abc.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65253100, -0.88111500, '0101000020E6100000357BA0151832ECBF2750C42286D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34270292895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34270292895.webp', 'https://www.flickr.com/photos/zaragozaantigua/34270292895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24246, 'Anselmo Coyne 1895', 'Anselmo Marâ”œآ،a Coyne Barreras naciâ”œâ”‚ en Pamplona en 1830, con ascendencia irlandesa, aprendiâ”œâ”‚ el oficio artesano de la fotografâ”œآ،a, y se instalâ”œâ”‚ en Zaragoza como asociado a Mariano Jâ”œâ•‘dez Ortiz ("Jâ”œâ•‘dez y Coyne"), en el despacho de â”œآ®ste, en el privilegiado observatorio de la calle Coso 33, frente a la fuente de Neptuno de la plaza de la Constituciâ”œâ”‚n. Tras la muerte de Jâ”œâ•‘dez, firmâ”œâ”‚ sus trabajos como "Coyne, sucesor de Jâ”œâ•‘dez", hasta que desde 1882 ya figuraba en solitario, hasta su propia muerte en 1896. En 1887 su estudio sufriâ”œâ”‚ un incendio, perdiâ”œآ®ndose su archivo y material fotogrâ”œأ­fico, y debiâ”œâ”‚ recomenzar desde cero. Es el iniciador de la saga zaragozana de los Coyne, y su legado visual es invaluable para conocer la ciudad de Zaragoza del â”œâ•‘ltimo tercio del siglo XIX. En la imagen, autorretrato suyo. Fuente visual: Foto Estudio Coyne, AHPZ.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65241800, -0.88079800, '0101000020E61000000C3B8C497F2FECBF2EA9DA6E82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31682025215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31682025215.webp', 'https://www.flickr.com/photos/zaragozaantigua/31682025215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24248, 'Pl. de la Constituciâ”œâ”‚n c.1864', 'Imagen centrada en la afrancesada y pagana fuente de Neptuno, soportada a regaâ”œâ–’adientes tras ser redenominada oficialmente como "de la Princesa". Su ubicaciâ”œâ”‚n en la plaza de la Constituciâ”œâ”‚n, casi donde se alzaba la desaparecida Cruz del Coso encrespaba los â”œأ­nimos de quienes no pararon hasta conseguir que esta fuente fuera sustituida aâ”œâ–’os despuâ”œآ®s por un monumento conmemorativo de los mâ”œأ­rtires de la religiâ”œâ”‚n y la patria, y esta funcional fuente fuera desterrada a parajes menos câ”œآ®ntricos. De momento, Neptuno seguâ”œآ،a prestando esencial servicio como abastecedor de agua de boca que redistribuâ”œآ،an luego aguadores y aguadoras. De fondo, fachada edilicia del Coso, en la que destacan los altos comerciales publicitarios que seâ”œâ–’alan la ubicaciâ”œâ”‚n de los gabinetes fotogrâ”œأ­ficos de Mariano Jâ”œâ•‘dez Ortâ”œآ،z, en el nâ”¬â•‘ 33, y el de Santos â”œأ¼lvarez Serra, en el nâ”¬â•‘ 35.', 1864, 1864, 1864, 'Siglo XIX', 'CENTRO', 41.65217000, -0.88071800, '0101000020E6100000F1F3DF83D72EECBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34545049520.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34545049520.webp', 'https://www.flickr.com/photos/zaragozaantigua/34545049520/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24251, 'Coso nâ”¬â•‘ 35, c.1863', 'El fotâ”œâ”‚grafo Mariano Jâ”œâ•‘dez y Ortiz posa en un autorretrato realizado en su gabinete sito en el â”œâ•‘ltimo piso del inmueble del Coso nâ”¬â•‘ 35 (antiguo nâ”¬â•‘ 18-19) "frente a la fuente" de la Princesa o de Neptuno en la plaza de la Constituciâ”œâ”‚n. Este zaragozano pionero de la fotografâ”œآ،a, hasta su fallecimiento en 1874 es autor de un singular repertorio de imâ”œأ­genes de la ciudad y algunos de sus habitantes. Prematuramente muerto, Anselmo Marâ”œآ،a Coyne Barreras mantendrâ”œآ،a durante unos aâ”œâ–’os la actividad fotogrâ”œأ­fica de su gabinete (establecido en el nâ”¬â•‘ 33 del Coso) mediante la Sociedad Industrial Jâ”œâ•‘dez y Coyne.', 1863, 1863, 1863, 'Siglo XIX', 'CENTRO', 41.65248100, -0.88070800, '0101000020E61000000E6B2A8BC22EECBF7521567F84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49802909812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49802909812.webp', 'https://www.flickr.com/photos/zaragozaantigua/49802909812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24253, 'Coyne y Tramullas 1909', 'Ignacio Coyne Lapetra y Antonio de Padua Tramullas posan en el estudio fotogrâ”œأ­fico de Coyne en la plaza de la Constituciâ”œâ”‚n, en los tiempos en que el primero tenâ”œآ،a abierto en la calle de San Miguel, en el tramo de los impares entre el paseo de la Constituciâ”œâ”‚n y la calle de los Sitios, el Cinematâ”œâ”‚grafo Coyne, primer local cinematogrâ”œأ­fico estable de Zaragoza. Con el tiempo, allâ”œآ، llegâ”œâ”‚ a exhibir producciones propias, de las que sâ”œâ”‚lo nos han llegado los tâ”œآ،tulos. El barcelonâ”œآ®s Tramullas llegâ”œâ”‚ a Zaragoza en 1899 y comenzâ”œâ”‚ trabajando como electricista en la empresa termoelâ”œآ®ctrica Electra Peral Zaragozana. En 1905 Ignacio Coyne inaugurâ”œâ”‚ su referido cine y Tramullas se cambiâ”œâ”‚ de acera para trabajar allâ”œآ، como operador de cabina, colaborando con Coyne de forma creciente, viajando ambos por pueblos y ciudades dando a conocer el nuevo Cine Parlante Coyne. En 1909, aâ”œâ–’o de esta imagen, se trasladaron al escenario bâ”œآ®lico de Melilla durante la guerra de Marruecos, y allâ”œآ، rodaron varios noticiarios grâ”œأ­ficos que se distribuyeron por toda Europa. Su colaboraciâ”œâ”‚n perdurâ”œâ”‚ hasta 1912, cuando prematuramente falleciâ”œâ”‚ Coyne y Tramullas pasâ”œâ”‚ a dedicarse en exclusiva a su propia productora, Sallumart (su apellido, al revâ”œآ®s) Films, que habâ”œآ،a creado en 1910, y prosigue en la tarea de filmar los principales acontecimientos ciudadanos y reportajes de actualidad, incluyendo alguna obra de ficciâ”œâ”‚n, como "El diablo estâ”œأ­ en Zaragoza" (1921), y reportajes documentales de temâ”œأ­tica agrâ”œآ،cola, como "El primer tractor en Zaragoza" (1915), realizado para la Granja Agrâ”œآ،cola.', 1909, 1909, 1909, 'Anos 1900', 'CENTRO', 41.65252100, -0.88084800, '0101000020E61000007DE71725E82FECBF037AE1CE85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50137271611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50137271611.webp', 'https://www.flickr.com/photos/zaragozaantigua/50137271611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24349, 'Torre de San Gil 1992', 'Torre de la iglesia de San Gil Abad tomada por Jasolo en 1992. Se restaurâ”œâ”‚ en 2006. Fuente: zaragozaciudad.net/zaragozafluye/2013/011101-torre-de-la-...', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65309300, -0.87971000, '0101000020E610000066DAFE959526ECBF8E1F2A8D98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14846037079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14846037079.webp', 'https://www.flickr.com/photos/zaragozaantigua/14846037079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24864, 'Pl. de la Constituciâ”œâ”‚n c.1901', 'Imagen nival de la plaza de la Constituciâ”œâ”‚n capturada al nivel peatonal, y centrada en el arranque de la calle de la Independencia, al fondo. A la derecha, vista parcial de la funcional fuente del pagano Neptuno, de la que seguâ”œآ،a fluyendo el vital lâ”œآ،quido, antes de ser erradicada y sustituida por una fuente ornamental mâ”œأ­s ortodoxa y canâ”œâ”‚nica. En primer plano, posiblemente uno de los aguadores que, tras reponer materia prima en la fuente, se encamina con su vehâ”œآ،culo de tracciâ”œâ”‚n animal a la rutinaria ruta de distribuciâ”œâ”‚n.', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.65217000, -0.88071800, '0101000020E6100000F1F3DF83D72EECBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34381046075.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34381046075.webp', 'https://www.flickr.com/photos/zaragozaantigua/34381046075/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24922, 'Muralla romana 2008', 'Restos de un torreâ”œâ”‚n de la muralla romana de Caesaraugusta, en la calle de los Mâ”œأ­rtires 2 y 4 (izquierda). El edificio que se levanta ahora allâ”œآ، los conserva a la vista en su interior. Fuente: arqueoguti.wordpress.com/2010/11/14/documentacion-geometr...', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.65238900, -0.88047400, '0101000020E6100000444E5FCFD72CECBF94A2957B81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33197053611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33197053611.webp', 'https://www.flickr.com/photos/zaragozaantigua/33197053611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25090, 'Santa Engracia 303', '"Ademâ”œأ­s de los innumerables mâ”œأ­rtires que padecieron en la persecuciâ”œâ”‚n de Diocleciano, sufriâ”œâ”‚ el martirio santa Engracia, natural de Zaragoza, con sus 18 compaâ”œâ–’eros, por los aâ”œâ–’os de 303", grabado de Mateo Gonzâ”œأ­lez, 1788. Al fondo, representaciâ”œâ”‚n de la muralla con la primitiva puerta sur, luego Cinegia. Fuente: lasfotosdebeatrizbm.blogspot.com', NULL, NULL, NULL, NULL, 'CENTRO', 41.65216200, -0.88075500, '0101000020E61000003A3B191C252FECBFD3D85E0B7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32583023483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32583023483.webp', 'https://www.flickr.com/photos/zaragozaantigua/32583023483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25094, 'Plâ”œأ­cido Domingo 1988', 'El cantante Plâ”œأ­cido Domingo (Madrid, 1941), en la calle de los Mâ”œأ­rtires, entrada del Tubo, donde sus abuelos abrieron la fonda La Cocineja, desde 1935 Casa Colâ”œأ­s. Fuente: Heraldo de Aragâ”œâ”‚n.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65259800, -0.88039900, '0101000020E61000009BCB0D863A2CECBFAEB7CD5488D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33124352136.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33124352136.webp', 'https://www.flickr.com/photos/zaragozaantigua/33124352136/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25132, 'Convento de San Francisco 1809', '"Place du Cofso a Sarragosse aprâ”œآ؟s le Siâ”œآ؟ge", litografâ”œآ،a de Engelman sobre dibujo de Bacler D''Albe, 1809. Ruinas del Convento de San Francisco de Zaragoza, bombardeado durante los sitios de 1808 y 1809. Parte de su solar serâ”œأ­ destinado a la sede de la Diputaciâ”œâ”‚n Provincial de Zaragoza. Fuente: Catâ”œأ­logo El municipio en Aragâ”œâ”‚n, DPZ, 2004.', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.65229400, -0.88107500, '0101000020E6100000A857CA32C431ECBF42B0AA5E7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18680553701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18680553701.webp', 'https://www.flickr.com/photos/zaragozaantigua/18680553701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25143, 'Plaza de la Constituciâ”œâ”‚n 1862', 'Dibujo de "Lâ”œâ”‚pez" publicado en el nâ”¬â•‘ 1 de "El Duende" (periâ”œâ”‚dico satâ”œآ،rico semanal editado en Zaragoza), como litografâ”œآ،a que ilumina un relato, o tragedia caricaturesca, titulada "La justicia de Neptuno", en la que la versiâ”œâ”‚n local del dios de las aguas la emprende con los guardias municipales ante su pasividad por el tremendo gallinero montado, en torno a los dominios de su fuente en la plaza de la Constituciâ”œâ”‚n, por soldados, aguadores, zagales de diligencias y fregatrices. En primer plano, el episodio de justicia neptuniana. Detrâ”œأ­s, la vacante fuente rodeada de los alborotadores, que siguen a lo suyo. Al fondo, fachada esquinera de la plaza-Coso Alto, con una parcial vista del nuevo edificio de la Diputaciâ”œâ”‚n, a la izquierda.', 1862, 1862, 1862, 'Siglo XIX', 'CENTRO', 41.65219700, -0.88107500, '0101000020E6100000A857CA32C431ECBF50C6F8307BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24633217091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24633217091.webp', 'https://www.flickr.com/photos/zaragozaantigua/24633217091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25186, 'Puerta Cinegia siglo III', 'Dibujo de Francisco Melâ”œآ®ndez expuesto en un panel a la entrada del centro comercial Puerta Cinegia, inaugurado en 2004 en la plaza de Espaâ”œâ–’a. Representa la ciudad romana de Caesaragusta, vista en el interior de su muralla del siglo III, con la Puerta Cinegia a la derecha.', 250, 200, 299, 'Siglo XIX', 'CENTRO', 41.65251100, -0.88066500, '0101000020E61000003C6BB75D682EECBFDFA3FE7A85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52492659400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52492659400.webp', 'https://www.flickr.com/photos/zaragozaantigua/52492659400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25273, 'El Tubo 1968', 'Instantâ”œأ­nea urbana del emboque de la populosa y turâ”œآ،stica calle de los Mâ”œأ­rtires con la plaza de Espaâ”œâ–’a al fondo, donde destaca el monumento a los Mâ”œأ­rtires. Este câ”œآ®ntrico enclave es conocido como la entrada al pequeâ”œâ–’o barrio del Tubo. En el quiosco de prensa de la derecha, un anuncio: "El Alcâ”œأ­zar. En directo el mundo entero".', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65237600, -0.88045900, '0101000020E6100000EF004F5AB82CECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14965606491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14965606491.webp', 'https://www.flickr.com/photos/zaragozaantigua/14965606491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25278, 'Acciâ”œâ”‚n Ciudadana, 1936', 'AHPZ. Archivo Coyne. Manuel Coyne. 1936. "Acciâ”œâ”‚n Ciudadana" en Zaragoza era una organizaciâ”œâ”‚n paramilitar formada el 18 de julio de 1936 por jefes y oficiales del Ejâ”œآ®rcito retirados por las reformas de Azaâ”œâ–’a que guardaban una calurosa animadversiâ”œâ”‚n hacia la Repâ”œâ•‘blica democrâ”œأ­tica. Segâ”œâ•‘n la prensa, pronto alcanzaron los 3.000 afiliados. Iban armados y con un brazalete blanco en el brazo izquierdo. Se ocuparon del abastecimiento de la ciudad, y desempeâ”œâ–’aron servicios de vigilancia, protecciâ”œâ”‚n y "limpieza". Tenâ”œآ،an a gala ser apolâ”œآ،ticos o, lo que es lo mismo, no tener matiz polâ”œآ،tico alguno, salvo "el honor de servir a Espaâ”œâ–’a en su causa mâ”œأ­s justa y mâ”œأ­s noble: la de salvarla de la tiranâ”œآ،a de Moscâ”œâ•‘". (Heraldo de Aragâ”œâ”‚n, 28-07-1936). En la imagen, personal de la derecha extrema, ultraderechista y de Acciâ”œâ”‚n Ciudadana, en la calle Mâ”œأ­rtires, muy satisfechos de limpiar el Tubo de rojos e indeseables al nuevo orden.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65237600, -0.88045900, '0101000020E6100000EF004F5AB82CECBFFF58880E81D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15023967441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15023967441.webp', 'https://www.flickr.com/photos/zaragozaantigua/15023967441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25293, 'Coso-Plaza de Espaâ”œâ–’a 1988', 'Imagen de la fachada del Coso en su tramo de la plaza de Espaâ”œâ–’a, cuando el inicio del piqueteo del tramo de los edificios del nâ”¬â•‘ 35 al 41, junto a la entrada a la calle Mâ”œأ­rtires (antigua Cinegio). A la izquierda, el nâ”¬â•‘ 33, todavâ”œآ،a con los sâ”œآ،mbolos de su larga etapa como sede provincial de Falange. El nâ”¬â•‘ 35, ya con la excavadora en plena acciâ”œâ”‚n, removiendo ruinas. Los nâ”œâ•‘meros 37-39, a la espera, con los reconocibles y visuales anuncios comerciales que los remataban. En los locales de estos edificios, algunos de los comercios de este sector urbano. Al fondo, visible por derribo, el torreâ”œâ”‚n que remata el patio del edificio gâ”œâ”‚tico-mudâ”œآ®jar de la esquina de Mâ”œأ­rtires-Cuatro de Agosto.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65256100, -0.88096600, '0101000020E6100000F969DC9BDF30ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17043337769.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17043337769.webp', 'https://www.flickr.com/photos/zaragozaantigua/17043337769/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25914, 'P.â”¬â•‘ de Fernando el Catâ”œâ”‚lico 1952', 'Inâ”œآ®dita imagen capturada en altura desde la novâ”œآ،sima torre de la marista Editorial Luis Vives SA y centrada en el tramo del paseo de Fernando el Catâ”œâ”‚lico comprendido entre el cruce con las calles de Manuel Serrano Sanz y de Luis Vives (en primer tâ”œآ®rmino) y la plaza de San Francisco (originalmente de Espaâ”œâ–’a, al fondo, con sus caracterâ”œآ،sticos porches). En ese momento todavâ”œآ،a alternaban los recientes edificios de viviendas de este moderno paseo con los solares de inmuebles que aâ”œâ–’os despuâ”œآ®s serâ”œآ،an construidos. Asâ”œآ،, en el lado de los pares (a la izquierda), figuran los ya terminados nâ”œâ•‘meros 56-48, 44 y 40 (esquinero con la calle de Andrâ”œآ®s Gimâ”œآ®nez Soler). En el lado de los impares destaca el inmediato solar esquinero con la calle de Luis Vives (futuro nâ”¬â•‘ 57), medianero con el ya construido nâ”¬â•‘ 55. Traqueteando hacia el principio de lâ”œآ،nea en la plaza de Espaâ”œâ–’a, una unidad tranviaria de la serie 200 (posiblemente la nâ”¬â•‘ 202) en servicio en la lâ”œآ،nea 11 "Parque" circula por un luminoso y bien tranquilo paseo. Fuente visual: aportaciâ”œâ”‚n personal y exclusiva de la familia de Sola al Gran Archivo Zaragoza Antigua (GAZA).', 1952, 1952, 1952, 'Anos 50', 'UNIVERSIDAD', 41.63919800, -0.89669300, '0101000020E610000008ABB184B5B1ECBF95D5743DD1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29096294037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29096294037.webp', 'https://www.flickr.com/photos/zaragozaantigua/29096294037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25294, 'Pl. de la Constituciâ”œâ”‚n 1928', 'Esos dâ”œآ،as de mayo, en el aâ”œâ–’o V de la Dictadura de Primo de Rivera, la ciudad era objeto de una enorme fiesta eucarâ”œآ،stica que culminâ”œâ”‚ con tremendas procesionarias peregrinantes y multinacionales ante la columna que llaman pilar. Hasta el Infante don Fernando de Baviera, de visita a las obras de la AGM y el campo de maniobras de San Gregorio, se apuntâ”œâ”‚ a la fiesta posterior, en la Lonja. En la Imagen, aspecto de la gran procesiâ”œâ”‚n que el dâ”œآ،a 21 habâ”œآ،a salido desde la basâ”œآ،lica concatedral, siguiâ”œâ”‚ por Jaime I, y llegâ”œâ”‚ a la plaza de la Constituciâ”œâ”‚n, donde la foto fue realizada, para continuar luego por el Coso Alto, Alfonso I, y vuelta al Pilar, a misa de las 8 de la tarde. Lo que parece una falla es una valiosa imagen de Marâ”œآ،a e hijo que se trajeron desde la villa y corte los "caballeros madrileâ”œâ–’os" sobre caballos mecâ”œأ­nicos. A la izquierda, aspecto de la fachada de los edificios de la plaza, con cartelâ”œâ”‚n del "Gran Cafâ”œآ® Royalty", establecimiento restaurador de "Lujo y Confort" especializado en cafâ”œآ®s, licores, cerveza y bocadillos, y que un par de aâ”œâ–’os antes habâ”œآ،a instalado el primer servicio de "cafâ”œآ® exprâ”œآ®s" de la ciudad. Aunque en la publicidad decâ”œآ،an estar en "plaza de la Constituciâ”œâ”‚n 2", su entrada efectiva era por la calle de los Mâ”œأ­rtires. A su lado, la sede de "La Voz de Aragâ”œâ”‚n", diario grâ”œأ­fico que llevaba apenas 3 aâ”œâ–’os funcionando, y que pese a su notable calidad, apenas durarâ”œأ­ otros 7 aâ”œâ–’os. Un poco mâ”œأ­s adelante, los bajos de la novâ”œآ،sima sede central del Banco Zaragozano. Fuente visual: revista "Nuevo Mundo" (Madrid), 1928.', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.65256100, -0.88096600, '0101000020E6100000F969DC9BDF30ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17284038591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17284038591.webp', 'https://www.flickr.com/photos/zaragozaantigua/17284038591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25301, 'Pl. de la Constituciâ”œâ”‚n 1936', 'Grupo de militares y personas celebrando el golpe de estado fallido del 18-19 de julio de 1936, en la plaza de la Constituciâ”œâ”‚n. Al fondo, el Banco de Espaâ”œâ–’a.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65222300, -0.88108500, '0101000020E61000008BE07F2BD931ECBF7959130B7CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20340105152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20340105152.webp', 'https://www.flickr.com/photos/zaragozaantigua/20340105152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
