INSERT INTO public.photos VALUES (21608, 'Banco Zaragozano 1929', 'Dibujo publicitario del edificio clasicista y eclâ”œآ®ctico del Banco Zaragozano proyectado en 1928 por Roberto Garcâ”œآ،a Ochoa Platas, e inaugurado en 1929. Sito en las fincas 47 y 49 del Coso, esquineras con las 1 y 3 de la calle de Don Jaime I, se trata de una construcciâ”œâ”‚n en chaflâ”œأ­n con torreâ”œâ”‚n, cuya câ”œâ•‘pula estâ”œأ­ recubierta de decoraciâ”œâ”‚n musivaria. Sus grandes arcos se inspiran en los del edificio anexo (Coso 43 y 45). La entidad fue fundada en 1910 y se extinguiâ”œâ”‚ en 2006. Fuente visual: www.facebook.com/photo.php?fbid=10203868909474524&set...', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65213500, -0.88006500, '0101000020E6100000EF552B137E29ECBFDAC9E02879D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29121379291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29121379291.webp', 'https://www.flickr.com/photos/zaragozaantigua/29121379291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21617, 'Pl. de la Constituciâ”œâ”‚n c.1920', 'Vista de la plaza de la Constituciâ”œâ”‚n hacia 1920, con el edificio de la Diputaciâ”œâ”‚n Provincial flanqueado por el esquinero del paseo de la Independencia, remodelado en 1916, y el de La Joyita, en el nâ”œâ•‘mero 1, con los andamios para su recrecimiento. Diversos medios de transporte, desde el coche de San Fernando hasta el tranvâ”œآ،a elâ”œآ®ctrico, pueblan la explanada. Fuente visual: www.iesporza.educa.aragon.es', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65210100, -0.88096800, '0101000020E610000026529ACDE330ECBF2E58AA0B78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32113131381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32113131381.webp', 'https://www.flickr.com/photos/zaragozaantigua/32113131381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
