INSERT INTO public.photos VALUES (21699, 'Seguros la Catalana 1930', 'Juan Mora. 1930 Imagen de la reciente sede de "La Sociedad Catalana de Seguros contra incendios" de la plaza de la Constituciâ”œâ”‚n, esquina con el paseo de la Independencia, diseâ”œâ–’ada en 1928 en el clasicista y eclâ”œآ®ctico lenguaje de carâ”œأ­cter monumental que caracteriza a los edificios de entidades bancarias levantados durante los aâ”œâ–’os 20-30. En su diseâ”œâ–’o ya se ha tenido en cuenta introducir porches con arcos de medio punto. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o VI, Nâ”¬â•‘ 63, diciembre 1930).', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65161000, -0.88102900, '0101000020E6100000917BBABA6331ECBF8FDFDBF467D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15487574359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15487574359.webp', 'https://www.flickr.com/photos/zaragozaantigua/15487574359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21703, 'Calle de San Miguel 1931', 'Imagen capturada en la calle de San Miguel junto a la fachada de las instalaciones de la compaâ”œâ–’â”œآ،a Elâ”œآ®ctricas Reunidas de Zaragoza SA sitas en el nâ”¬â•‘ 8 de esa calle. Este edificio fue diseâ”œâ–’ado por Fâ”œآ®lix Navarro Pâ”œآ®rez en 1880 para El Prado Aragonâ”œآ®s, teatro que en 1882 fue redenominado Teatro Goya hasta su cierre y venta en 1893 a la empresa termoelâ”œآ®ctrica Electra Peral Zaragozana, que desde 1904 era parte de Sociedades Elâ”œآ®ctricas Reunidas, y desde 1910 de Elâ”œآ®ctricas Reunidas de Zaragoza. En la imagen aparece en toda su plenitud la fachada principal del original teatro, esquinero entre la calle de San Miguel y la calle de Isaac Peral, asâ”œآ، denominada por la impronta de la elâ”œآ®ctrica factorâ”œآ،a. Este edificio perdurâ”œâ”‚, con leves reformas, hasta su derribo integral en 1958 para construir sobre su solar una nueva y moderna sede de la empresa elâ”œآ®ctrica. Al fondo, en la otra esquina, vista parcial del Teatro Circo. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65101600, -0.88073900, '0101000020E6100000CFF9298E032FECBF1C96067E54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15713611427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15713611427.webp', 'https://www.flickr.com/photos/zaragozaantigua/15713611427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21738, 'La Catalana 1931', 'Foto: Lucien Roisin, 1931. En 1930 se inaugurâ”œâ”‚ el edificio del paseo Independencia 1, propiedad de seguros La Catalana. Abajo, tranvâ”œآ،a nâ”œâ•‘mero 53. Fuente: "Zaragoza, aâ”œâ–’os 20", IFC, 2014.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65167800, -0.88105200, '0101000020E61000009C69C2F69331ECBFE7C2482F6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21583378261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21583378261.webp', 'https://www.flickr.com/photos/zaragozaantigua/21583378261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21739, 'Pl. de Espaâ”œâ–’a 1936', 'Vista de los bancos Zaragozano y de Espaâ”œâ–’a, â”œآ®ste â”œâ•‘ltimo con aâ”œâ–’adidos propios de la â”œآ®poca, en la que ademâ”œأ­s de cambiar el nombre de la plaza, se mostraba en carteles la imagen del general golpista Francisco Franco. Arriba a la derecha, "Viva Espaâ”œâ–’a". Sobre el Banco Zaragozano, banderas de la Espaâ”œâ–’a fascista. Fuente: www.facebook.com/photo.php?fbid=893527074077153&set=g...', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65190200, -0.88065600, '0101000020E61000006FD6E07D552EECBF3719558671D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21728063345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21728063345.webp', 'https://www.flickr.com/photos/zaragozaantigua/21728063345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
