INSERT INTO public.photos VALUES (21784, 'Coso Medio 1930', 'Coso a la altura del Teatro Principal. A la izquierda, la calle de los Sitios. Al fondo, la plaza de la Constituciâ”œâ”‚n. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65202100, -0.88008800, '0101000020E6100000FA43334FAE29ECBF11A7936C75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23221666466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23221666466.webp', 'https://www.flickr.com/photos/zaragozaantigua/23221666466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21785, 'Coso Medio 1930', 'Vista de la entrada a la calle de Don Jaime I desde el tramo medio del Coso, con la plaza de la Constituciâ”œâ”‚n (hoy de Espaâ”œâ–’a) a la izquierda y fuera de plano. Contrasta el flamante modelo de automâ”œâ”‚vil estadounidense de primer plano con el carro tirado por un caballo que se ve detrâ”œأ­s. Al fondo, la torre de la Seo.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65202100, -0.88008800, '0101000020E6100000FA43334FAE29ECBF11A7936C75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23222731796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23222731796.webp', 'https://www.flickr.com/photos/zaragozaantigua/23222731796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21792, 'Coso Medio 1933', 'Foto tomada el dâ”œآ،a de la inauguraciâ”œâ”‚n del cafâ”œآ® bar Miami, en el nâ”œâ•‘mero 74 del Coso Medio, esquina con la calle de los Sitios (derecha). Fuente: Cafâ”œآ®s de Zaragoza. Su biografâ”œآ،a, 1797-1939, IFC, 2015.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65173400, -0.87980800, '0101000020E61000001B4B581B6327ECBF7BD80B056CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24308032066.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24308032066.webp', 'https://www.flickr.com/photos/zaragozaantigua/24308032066/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21795, 'Pl. de Espaâ”œâ–’a 1938', 'Imagen capturada por un miembro de la "Legiâ”œâ”‚n Condor", desde el paseo de la Independencia, de la nueva plaza de Espaâ”œâ–’a, antes denominada "de la Constituciâ”œâ”‚n", cuando la habâ”œآ،a. En primer plano, una pancarta enfatiza uno de los significados que la fecha del "18 de julio" (de 1936) tenâ”œآ،a para quienes ese dâ”œآ،a se levantaron en armas contra la democracia. Al fondo, la soleada fachada del Coso, con la entrada a la calle de los Mâ”œأ­rtires.', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65170200, -0.88119200, '0101000020E61000000CE6AF90B932ECBF705E9CF86AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24805216961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24805216961.webp', 'https://www.flickr.com/photos/zaragozaantigua/24805216961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21864, 'Coso Medio 1933', 'Imagen capturada en el arranque del tramo medio del Coso, y centrada en un tranvâ”œآ،a de la lâ”œآ،nea 1 "Bajo Aragâ”œâ”‚n" (posiblemente, una unidad de la serie "cerrados" 36-39), manejado por miembros del Cuerpo de Seguridad y Asalto durante la huelga sindical del sector del comercio y los servicios pâ”œâ•‘blicos de mayo de ese aâ”œâ–’o, tras los incidentes ocasionados en unidades de las lâ”œآ،neas de Torrero, estaciâ”œâ”‚n de Madrid, Delicias, Gâ”œأ­llego y Bajo Aragâ”œâ”‚n. A la izquierda, fuera de plano, el emboque a la calle de Don Jaime I. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65182800, -0.87985200, '0101000020E6100000033FAA61BF27ECBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36355758776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36355758776.webp', 'https://www.flickr.com/photos/zaragozaantigua/36355758776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21868, 'Calle de San Miguel 1933', 'Imagen capturada en la terraza del moderno Teatro-Cine Goya poco antes del inicio de una de las vespertinas sesiones al aire libre organizadas para tratar de mitigar el severo estâ”œآ،o local. La proyecciâ”œâ”‚n, en este caso, serâ”œآ،a la gran producciâ”œâ”‚n norteamericana de la Metro-Goldwyn-Mayer &quot;Mata-Hari&quot; (1931), protagonizada por Greta Garbo y Ramâ”œâ”‚n Novarro. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65116000, -0.88062100, '0101000020E6100000537765170C2EECBF4F3BFC3559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36507496101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36507496101.webp', 'https://www.flickr.com/photos/zaragozaantigua/36507496101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21871, 'Pl. de la Constituciâ”œâ”‚n 1931', 'Imagen centrada en la fachada del Gran Hotel de Europa tras el cese de su tradicional actividad, ya cerrado y en modo espera de la piqueta que lo derribarâ”œآ،a poco despuâ”œآ®s. Este emblemâ”œأ­tico establecimiento iniciâ”œâ”‚ sus actividades hacia 1845 como Fonda de Europa, en terrenos del antiguo y gran hospital de Ntra. Sra. de Gracia. En el momento de capturar esta imagen el edificio del hotel estaba etiquetado como un caserâ”œâ”‚n cargado de historia e historias, mas era considerado arcaico, decadente, viejo, que desdecâ”œآ،a a los modernos edificios del centro de la ciudad. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65179300, -0.88028300, '0101000020E61000004D310741472BECBF8061F9F36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37683796132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37683796132.webp', 'https://www.flickr.com/photos/zaragozaantigua/37683796132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21962, 'Plaza Espaâ”œâ–’a 1944', 'Trabajos de apilamiento de nieve en la plaza de Espaâ”œâ–’a, para despejar el trâ”œأ­nsito rodado, tras la intensa nevada del 24 y 25 de febrero. Segâ”œâ•‘n la prensa de la â”œآ®poca, es una de la mayores nevadas que se recuerdan. En el centro, el monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y de la Patria, ante la embocadura del Coso Alto. A su derecha y al fondo, la sede provincial de la Falange Espaâ”œâ–’ola Tradicionalista y de las JONS, en el nâ”¬â•‘ 33 del Coso recayente a la plaza. Fuente: Colecciâ”œâ”‚n particular.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20864992522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20864992522.webp', 'https://www.flickr.com/photos/zaragozaantigua/20864992522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
