INSERT INTO public.photos VALUES (22179, 'Fernando Fernâ”œأ­n Gâ”œâ”‚mez 1958', 'Estreno en el cine Goya de "La vida por delante" (1958), dirigida y protagonizada por Fernando Fernâ”œأ­n Gâ”œâ”‚mez. El actor y su pareja, Analâ”œآ،a Gadâ”œآ®, tambiâ”œآ®n protagonista de la cinta, aparecen a la derecha.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65109900, -0.88065700, '0101000020E610000086CABF96572EECBFAABA473657D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31746901924.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31746901924.webp', 'https://www.flickr.com/photos/zaragozaantigua/31746901924/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22220, 'Plaza de Espaâ”œâ–’a c.1954', 'Luminosa imagen capturada desde cierta altura y centrada en la plaza de Espaâ”œâ–’a y el principio del antiguo bulevar del paseo de la Independencia, donde destaca la terminal de la tranviaria lâ”œآ،nea 11. Parque con una unidad de la serie 200 (subserie 209-213) a punto de iniciar recorrido hacia la Feria de Muestras. El fondo edilicio viene marcado por el esquinero edificio del Banco Hispano Americano, y por la novâ”œآ،sima fachada del palacio de la Diputaciâ”œâ”‚n Provincial, todavâ”œآ،a sin el râ”œâ”‚tulo que lo identifica. En primer plano, la arbolada y aparentemente peatonal plaza, antes del tsunami automovilâ”œآ،stico.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65212000, -0.88105200, '0101000020E61000009C69C2F69331ECBFA4880CAB78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48316012256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48316012256.webp', 'https://www.flickr.com/photos/zaragozaantigua/48316012256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
