INSERT INTO public.photos VALUES (22292, 'Plaza de Espaâ”œâ–’a 1967', 'Vista aâ”œآ®rea de la plaza de Espaâ”œâ–’a de Zaragoza en 1967. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œآ® Marâ”œآ،a Sanz Gonzâ”œأ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65204900, -0.88094800, '0101000020E61000005F402FDCB930ECBFDB31755776D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15304646434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15304646434.webp', 'https://www.flickr.com/photos/zaragozaantigua/15304646434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25633, 'La Romareda 1957', 'Desde la altura de la Residencia Sanitaria Josâ”œآ® Antonio, una despejada vista panorâ”œأ­mica con un primer plano del nuevo Estadio Municipal de La Romareda, en el proyectado Polâ”œآ،gono Gran Vâ”œآ،a. Detrâ”œأ­s e inmediata, la antigua carretera de Valencia, surtida de torres y campos de cultivo, y al fondo, agreste panorama hasta el entorno del Hospital Psiquiâ”œأ­trico Nuestra Seâ”œâ–’ora del Pilar, que alcanza incluso hasta el Grupo de Viviendas "Arzobispo Domenech" en la Vâ”œآ،a Hispanidad. Fuente visual: AMZ', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63655900, -0.90191300, '0101000020E6100000BCCADAA678DCECBFBB7CEBC37AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40118878123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40118878123.webp', 'https://www.flickr.com/photos/zaragozaantigua/40118878123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22430, 'Pl. de Espaâ”œâ–’a 1967', 'Unidad de la serie "300" de la tranviaria lâ”œآ،nea 11 "Parque", llegando a su terminal situada en la plaza de Espaâ”œâ–’a, donde procederâ”œأ­ a dar la vuelta para recomenzar el trayecto hasta el antiguo parque de Buenavista. A finales de ese aâ”œâ–’o, esta lâ”œآ،nea serâ”œآ،a unificada con la 13, "San Josâ”œآ®", conformando la nueva lâ”œآ،nea "Parque-San Josâ”œآ®", que con el guarismo 11 supervivirâ”œآ،a prestando servicio pâ”œâ•‘blico hasta enero de 1976, en que fue ejecutada su clausura, siendo entonces la â”œâ•‘ltima en la ciudad de este antiguo y apreciado gâ”œآ®nero de transporte urbano, en su versiâ”œâ”‚n clâ”œأ­sica. Al fondo, a la derecha, recayente al paseo de la Independencia, la imponente mole de la moderna gran superficie comercial en vertical de la Sociedad Espaâ”œâ–’ola de Precios â”œأœnicos, durante su â”œâ•‘ltima fase de construcciâ”œâ”‚n, antes de ser inaugurada ese mismo aâ”œâ–’o. Fuente: www.ebay.es/', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65191800, -0.88069800, '0101000020E61000002AE27492AD2EECBF3DD68C0C72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29106616025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29106616025.webp', 'https://www.flickr.com/photos/zaragozaantigua/29106616025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22502, 'Coso Medio c.1964', 'Imagen de la composiciâ”œâ”‚n tranviaria M+R 109 en servicio en la lâ”œآ،nea 17. Las Fuentes capturada en el arranque del Coso Medio y encaminada hacia la perifâ”œآ®rica barriada que le daba nombre. Hacia el fondo y a la izquierda, guardia urbano regula el trâ”œأ­fico en la plaza de Espaâ”œâ–’a. Tras el tranvâ”œآ،a, la achaflanada esquina del Banco Zaragozano que indica el principio de la calle de Don Jaime I.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65186300, -0.87982800, '0101000020E6100000E25CC30C8D27ECBF793C2D3F70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49903643998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49903643998.webp', 'https://www.flickr.com/photos/zaragozaantigua/49903643998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22540, 'Pl. de Espaâ”œâ–’a 1972', 'Tranvâ”œآ،a 209 de la lâ”œآ،nea 11 ("Parque-San Josâ”œآ®") en la parada de la Plaza de Espaâ”œâ–’a repostando pasaje en su camino hacia San Josâ”œآ®. Fuente visual: www.flickr.com/photos/jhm0284/5812531521/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65200000, -0.88055300, '0101000020E610000049A12C7C7D2DECBFFA7E6ABC74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14894953422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14894953422.webp', 'https://www.flickr.com/photos/zaragozaantigua/14894953422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22573, 'Calle Don Jaime I, 1973', 'Câ”œآ®sar Sâ”œأ­nchez Vâ”œأ­zquez. 1973. Imagen de la fachada del edificio del estudio de "Jarke", en la calle Don Jaime I, 2. En 1918, Câ”œآ®sar Gracia Jarke se estableciâ”œâ”‚ como fotâ”œâ”‚grafo con el nombre de â”¬آ½Jarkeâ”¬â•—, (continuando luego su hijo Josâ”œآ® Antonio) especializâ”œأ­ndose en fotografâ”œآ،a industrial aunque, como buen imaginero, tocaba todos los palos. Fuente visual: www.facebook.com/groups/fotosantiguasdezaragoza/792846500...', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65202200, -0.87992900, '0101000020E6100000DAA9B9DC6028ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15413073919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15413073919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15413073919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22693, 'Pl. de Espaâ”œâ–’a 1970', 'Colorista imagen de la plaza de Espaâ”œâ–’a centrada en el paâ”œâ–’o de la fachada entre las calles de los Mâ”œأ­rtires y Don Jaime I, cuando los remates edilicios estaban poblados de luminosos anuncios comerciales de neâ”œâ”‚n, de considerable efecto visual nocturno. El denso trâ”œأ­fico rodado todavâ”œآ،a incluye elementos tranviarios. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso dâ”œآ،a de junio de 1970, durante su paso por la ciudad. Fuente visual: www.flickr.com/photos/intervene/4159219218/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65200200, -0.88073900, '0101000020E6100000CFF9298E032FECBF9B7631CD74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27314010316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27314010316.webp', 'https://www.flickr.com/photos/zaragozaantigua/27314010316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22694, 'Pl. de Espaâ”œâ–’a 1970', 'Entraâ”œâ–’able y colorista imagen parcial de la plaza de Espaâ”œâ–’a, junto al banco del â”œآ،dem, cuando todavâ”œآ،a era posible asistir al tranviario cruce de la lâ”œآ،nea 5 ("Venecia-Delicias"), en este caso la veterana composiciâ”œâ”‚n 59+87 en direcciâ”œâ”‚n hacia la plaza de Huesca, con la lâ”œآ،nea 11 ("Parque-San Josâ”œآ®"), una novâ”œآ،sima unidad 300 en direcciâ”œâ”‚n a la calle de Suiza del barrio de San Josâ”œآ®. Un aâ”œâ–’o despuâ”œآ®s, la lâ”œآ،nea 5 fue desmantelada. La lâ”œآ،nea 11 fue la â”œâ•‘ltima del antiguo y provinciano tranvâ”œآ،a, clausurada a comienzos de 1976. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso dâ”œآ،a de junio de 1970, durante su paso por la ciudad. Fuente visual: www.flickr.com/photos/intervene/1994932855/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65191300, -0.88037400, '0101000020E610000062F54718062CECBF2B6B9BE271D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27315484876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27315484876.webp', 'https://www.flickr.com/photos/zaragozaantigua/27315484876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22804, 'Coso Medio 1972', 'Antolâ”œâ”‚gica imagen centrada en el veterano paso de peatones habilitado en el arranque del tramo medio del Coso, entre la esquina de la plaza de Espaâ”œâ–’a inmediata al homâ”œâ”‚nimo Banco (a la izquierda y fuera de plano), y el inmueble de los nâ”œâ•‘meros 43-45 del Coso del fondo, en cuyos bajos comerciales destaca la Farmacia Râ”œآ،os. A la izquierda, ingreso al Tubo por la calle de los Mâ”œأ­rtires. El firme mojado por la lluvia primaveral conserva el antiguo pavimento adoquinado, trufado de los modernos parches asfâ”œأ­lticos, ademâ”œأ­s del trazado de la tranviaria lâ”œآ،nea 11. Parque-San Josâ”œآ®. Por este estratâ”œآ®gico cruce, y cuando el semâ”œأ­foro lo disponâ”œآ،a, circulaba el intenso trâ”œأ­fico motorizado que desde la calle de Don Jaime I se encaminaba hacia las carreteras de Madrid y de Valencia.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65204000, -0.88025800, '0101000020E6100000145B41D3122BECBF88D7F50B76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48126008662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48126008662.webp', 'https://www.flickr.com/photos/zaragozaantigua/48126008662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22824, 'Coso medio 1974', 'Imagen capturada en el tramo medio del Coso y centrada en un coche de la serie 200 en servicio en la tranviaria lâ”œآ،nea 11. Parque-San Josâ”œآ® encaminado hacia este barrio.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65194300, -0.87991400, '0101000020E6100000855CA9674128ECBF96ED43DE72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51825479122.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51825479122.webp', 'https://www.flickr.com/photos/zaragozaantigua/51825479122/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22825, 'Plaza de Espaâ”œâ–’a 1974', 'Imagen capturada en la plaza de Espaâ”œâ–’a y centrada en un coche de la serie 200 en servicio en la tranviaria lâ”œآ،nea 11. Parque-San Josâ”œآ®, regresando de este barrio, donde estaban ubicado (polâ”œآ،gono de Miraflores) el ferial de atracciones durante las Fiestas del Pilar, tal y como luce el cartel del frontal. Al fondo, el inmueble del nâ”¬â•‘ 60 del Coso, esquinero con la calle de Los Sitios, que una reforma posterior (al principio de los aâ”œâ–’os 90) le aâ”œâ–’adirâ”œأ­ una altura extra de un par de pisos.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65210400, -0.88064400, '0101000020E61000005E656D533C2EECBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51828834181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51828834181.webp', 'https://www.flickr.com/photos/zaragozaantigua/51828834181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22827, 'Calle de San Miguel 1970', 'Decembrina y nocturna escena capturada desde la calle de los Sitios y centrada en la achaflanada fachada de la sede social de la empresa Elâ”œآ®ctricas Reunidas de Zaragoza que destaca decorada con iluminaciâ”œâ”‚n de temporada basada en elementos astrolâ”œâ”‚gicos y mitolâ”œâ”‚gicos varios. En un entorno de calles adoquinadas, la calle de San Miguel aparece asfaltada de forma pionera.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65094100, -0.88054700, '0101000020E6100000C0E8F2E6702DECBF1250E10852D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52838332327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52838332327.webp', 'https://www.flickr.com/photos/zaragozaantigua/52838332327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23062, 'Plaza de Espaâ”œâ–’a 1992', 'Imagen capturada en la plaza de Espaâ”œâ–’a y orientada hacia la fachada del Coso recayente a ella. En primer tâ”œآ®rmino, la rotonda automovilâ”œآ،stica con el Monumento a los Mâ”œأ­rtires de la Religiâ”œâ”‚n y la Patria en el centro. Al fondo y hasta la entrada a la calle de los Mâ”œأ­rtires, inmuebles del Coso en trâ”œأ­nsito hacia la rehabilitaciâ”œâ”‚n y/o derribo, destacando en el solar del ya desaparecido nâ”¬â•‘ 35 la efâ”œآ،mera exhibiciâ”œâ”‚n de dos pancartas reivindicativas, una advirtiendo de los riesgos de la central nuclear mâ”œأ­s antigua de Espaâ”œâ–’a, y la otra una carta a los reyes magos pidiendo la libertad del insumiso Antonio Oriol.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65204000, -0.88104100, '0101000020E6100000A2EC2DE57C31ECBF88D7F50B76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50509020197.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50509020197.webp', 'https://www.flickr.com/photos/zaragozaantigua/50509020197/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23130, 'Pl. de Espaâ”œâ–’a 2006', 'Foto: Pedro Etura. Vista de la plaza de Espaâ”œâ–’a, con el Coso Medio al fondo a la izquierda, y el paseo de la Independencia a la derecha. Tras el monumento a los Mâ”œأ­rtires, el Banco de Espaâ”œâ–’a. Este diseâ”œâ–’o de rotonda automovilâ”œآ،stica, implantado en 1961 y modificado en 1976 y 2002, serâ”œأ­ readaptado con motivo de las obras de la segunda fase de la lâ”œآ،nea 1 del tranvâ”œآ،a (2011-2013). Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65214900, -0.88100000, '0101000020E6100000FED478E92631ECBF3F8F519E79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31610110310.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31610110310.webp', 'https://www.flickr.com/photos/zaragozaantigua/31610110310/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23169, 'Calle San Miguel 2009', 'Foto: Juan Carlos Arcos. Estado de las obras en el solar del antiguo cine Goya (1932-2005), con la conservaciâ”œâ”‚n de su fachada a la calle San Miguel 7 (al fondo). Las catas arqueolâ”œâ”‚gicas dieron como resultado el hallazgo de vestigios del Hospital de Gracia, de una casa de â”œآ®poca islâ”œأ­mica y de una edificaciâ”œâ”‚n romana. Fueron considerados poco relevantes, asâ”œآ، que se siguiâ”œâ”‚ con el proyecto de nuevo edificio comercial. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'CENTRO', 41.65115500, -0.88059200, '0101000020E6100000C0D02346CF2DECBF3ED00A0C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33054367622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33054367622.webp', 'https://www.flickr.com/photos/zaragozaantigua/33054367622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23204, 'Pl. de Espaâ”œâ–’a 2010', 'Foto: Vâ”œآ،ctor Lax. Una grâ”œâ•‘a coloca en la plaza de Espaâ”œâ–’a una maqueta a tamaâ”œâ–’o real de un fragmento de vagâ”œâ”‚n del futuro tranvâ”œآ،a de la ciudad, en abril de 2010. Se trataba de una promociâ”œâ”‚n para dar a conocer este nuevo servicio, que entrâ”œâ”‚ en funcionamiento un aâ”œâ–’o despuâ”œآ®s. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CENTRO', 41.65213300, -0.88089300, '0101000020E61000007DCF48844630ECBF39D2191879D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32670741704.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32670741704.webp', 'https://www.flickr.com/photos/zaragozaantigua/32670741704/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23274, 'Hospital de Nuestra Seâ”œâ–’ora de Gracia 1808', '"Ruinas del patio del Hospital General de Nuestra Seâ”œâ–’ora de Gracia", Serie Ruinas de Zaragoza, de Juan Gâ”œأ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œأ­diz, 1812. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20747011656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20747011656.webp', 'https://www.flickr.com/photos/zaragozaantigua/20747011656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23275, 'Hospital Nuestra Seâ”œâ–’ora de Gracia 1808', '"Vista del costado de la Yglesia del Hospital General de Nuestra Seâ”œâ–’ora de Gracia", grabado de la serie "Ruinas de Zaragoza" de Juan Gâ”œأ­lvez y Fernando Brambila, 1812-1813. Aspecto del interior de las instalaciones del Hospital, con la espadaâ”œâ–’a de la entrada a la iglesia al fondo a la izquierda, en una vista trasera del mismo edificio que aparece en el grabado "Vista de la calle del Coso" de la misma colecciâ”œâ”‚n (www.flickr.com/photos/zaragozaantigua/19083373031/). Fuente visual: www.bibliotecavirtualdeandalucia.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65179100, -0.88049400, '0101000020E61000000B60CAC0012DECBFE06932E36DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21085205636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21085205636.webp', 'https://www.flickr.com/photos/zaragozaantigua/21085205636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23276, 'Coso 1808', 'Versiâ”œâ”‚n de la "Vista de la calle del Coso" de Gâ”œأ­lvez y Brambila. Muestra el espacio del Coso de Zaragoza que ocuparâ”œأ­ despuâ”œآ®s la plaza de San Fernando, actual plaza de Espaâ”œâ–’a, visto desde la confluencia con la actual calle de Don Jaime. A la izquierda, la iglesia del Hospital de Nuestra Seâ”œâ–’ora de Gracia o de Locos. A la derecha, con tres torretas, la entrada a la iglesia del convento de San Francisco, al que tambiâ”œآ®n corresponde la torre alta de la izquierda. Aunque no se ve, entrambos edificios se halla el estrecho camino de Santa Engracia, hoy paseo de la Independencia. A la derecha, ruinas de la Cruz del Coso, tras las que continâ”œâ•‘a la calle, en la zona del palacio de Sâ”œأ­stago. En primer plano, como principal variante del dibujo original, las Hermanas de la Caridad de Santa Ana trasladan a los enfermos del Hospital a la Casa de Misericordia. Su directora, la Madre Rafols, pasâ”œâ”‚ a ser legendaria heroâ”œآ،na de la contienda, y figura simbâ”œâ”‚lica de los reaccionarios locales, desde la llegada de la Segunda Repâ”œâ•‘blica y sobre todo a partir de la Guerra Civil. Hay quien asegura que los locos que lograron escapar por su propio pie del Hospital, huyeron hasta el monte de Torrero, donde una parte se lanzâ”œâ”‚ al Canal Imperial, pereciendo ahogados; y que los supervivientes, al ver a las monjas que corrâ”œآ،an tras ellos, las siguieron cual corderillos. Fuente visual: Postal editada por las Hermanas de la Caridad de Santa Ana de Zaragoza.', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65213600, -0.88081000, '0101000020E61000001DACFF73982FECBFAA45443179D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30500435730.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30500435730.webp', 'https://www.flickr.com/photos/zaragozaantigua/30500435730/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23605, 'Plaza de Espaâ”œâ–’a 1952', 'AHPZ-Archivo Coyne, Manuel Coyne, 1952. Plaza de Espaâ”œâ–’a desde el Coso Medio.', 1952, 1952, 1952, 'Anos 50', 'CENTRO', 41.65195900, -0.87985500, '0101000020E6100000481B47ACC527ECBF9BAA7B6473D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14885938632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14885938632.webp', 'https://www.flickr.com/photos/zaragozaantigua/14885938632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23608, 'Coso Medio 1955', 'El coche de caballo era signo de ostentaciâ”œâ”‚n socioeconâ”œâ”‚mica, exclusiva seâ”œâ–’al de pertenencia al estamento, luego clase, dominante. Zaragoza tenâ”œآ،a su parque de coches a propulsiâ”œâ”‚n de sangre, y al principio era cosa de condes, marqueses, barones, y del arzobispo catâ”œâ”‚lico. En el XIX se les uniâ”œâ”‚ el Capitâ”œأ­n General de la Regiâ”œâ”‚n Militar, el Gobernador Civil, y el presidente de la DPZ. El alcalde tenâ”œآ،a uno, alquilado, de un solo caballo (de 1923 es el primer automâ”œâ”‚vil municipal). Tambiâ”œآ®n se lo agenciaron los miembros de la clase dirigente que, aun sin tâ”œآ،tulo nobiliario, tenâ”œآ،an excelente talonario. En los aâ”œâ–’os 60 del pasado siglo quedaban unos cinco coches de caballos traqueteando por la ciudad. En la imagen, coche de caballo aparcado al lado del Teatro Principal, en el Coso Medio. Detrâ”œأ­s, junto a la embocadura a la calle de los Sitios, un trolebâ”œâ•‘s de la lâ”œآ،nea del Gâ”œأ­llego. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65191100, -0.87980700, '0101000020E6100000045779026127ECBF8A73D4D171D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15180539329.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15180539329.webp', 'https://www.flickr.com/photos/zaragozaantigua/15180539329/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23609, 'Coso 1963', 'Foto Robert A. Hall, julio de 1963. Tramo del Coso Medio en las inmediaciones con la plaza de Espaâ”œâ–’a (al fondo). En el centro de la imagen, calle de Los Sitios. Fuente: Los tranvâ”œآ،as de Zaragoza, 1985.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65189400, -0.87982900, '0101000020E6100000F850A2258F27ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15263088053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15263088053.webp', 'https://www.flickr.com/photos/zaragozaantigua/15263088053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23613, 'Coso Medio 1959', 'El Teatro Principal desde cierta altura, en una vista del Coso que alcanza hasta el colegio de los Escolapios, al fondo. El teatro presenta el aspecto exterior tras la reforma proyectada por Josâ”œآ® Beltrâ”œأ­n y Regino Borobio e inaugurada en 1940, aunque sin la decoraciâ”œâ”‚n escultâ”œâ”‚rica de la fachada, que finalmente se instalarâ”œآ،a a finales de los aâ”œâ–’os 60. En la acera solanera del Coso destacan los toldos de los comercios, y sobre el inmueble del nâ”¬â•‘ 1 de la plaza de Espaâ”œâ–’a y el Casino Mercantil los palomares que hacen de remate, ambos luego desaparecidos. Junto a los â”œأ­rboles de la plaza de Espaâ”œâ–’a, un guardia urbano ordena el trâ”œأ­fico de personas, tranvâ”œآ،as y demâ”œأ­s vehâ”œآ،culos. Fuente: Instituto Amatller de Arte Hispâ”œأ­nico (Arxiu Mas), convertida luego en postal por la editorial Garcâ”œآ،a Garrabella.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65189400, -0.87982900, '0101000020E6100000F850A2258F27ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15704941220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15704941220.webp', 'https://www.flickr.com/photos/zaragozaantigua/15704941220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23619, 'Calle Don Jaime I 1899', '"Rue de la Bourse", Renâ”œآ® Ancely, 1899. Imagen de la entrada a la calle de Don Jaime I desde el Coso. En el original, esta calle aparece denominada "Rue de la Bourse", por conducir a la Lonja ("Bourse"). Al fondo, despunta la torre de la Seo. Sobre el firme los primitivos tendidos tranviarios por donde transitaban las lâ”œآ،neas del Arrabal (por la calle Don Jaime I), la de Circunvalaciâ”œâ”‚n (Coso), y la del Bajo Aragâ”œâ”‚n, hasta la Estaciâ”œâ”‚n de Cappa. El fresco, aun con sol de invierno, se combate mejor con capa. Fuente: www.georgesancely.com/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65202100, -0.88008800, '0101000020E6100000FA43334FAE29ECBF11A7936C75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27306160341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27306160341.webp', 'https://www.flickr.com/photos/zaragozaantigua/27306160341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23622, 'Coso Medio 1954', 'Dos trolebuses (un BUT de 1 piso, y un VETRA) de la nueva lâ”œآ،nea del Gâ”œأ­llego, aparcados en el Coso Medio durante su oficial puesta de largo, con la plaza de Espaâ”œâ–’a al fondo. La Terminal de lâ”œآ،nea se estableciâ”œâ”‚ aâ”œâ–’os despuâ”œآ®s en la calle de la Verâ”œâ”‚nica. Fuente visual: HA', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65182800, -0.87985200, '0101000020E6100000033FAA61BF27ECBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32514782406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32514782406.webp', 'https://www.flickr.com/photos/zaragozaantigua/32514782406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23623, 'Coso Medio 1954', 'En el Coso Medio, tramo comprendido entre las plazas de Espaâ”œâ–’a y de San Miguel, imagen en primer plano de dos trolebuses durante la inauguraciâ”œâ”‚n oficial del nuevo servicio de la lâ”œآ،nea Gâ”œأ­llego que conectaba esta terminal, esquinera con la calle de Blancas, con la del puente del râ”œآ،o Gâ”œأ­llego situado a la entrada al barrio de Santa Isabel. Los trolebuses estacionados han llegado desde la calle de Don Jaime I, cuyo entorno alrededor de la esquina del Banco Zaragozano muestra una bulliciosa actividad de viandantes y vehâ”œآ،culos. Fuente visual: AHPZ.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.65182800, -0.87985200, '0101000020E6100000033FAA61BF27ECBFFD4E93196FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33477861516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33477861516.webp', 'https://www.flickr.com/photos/zaragozaantigua/33477861516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23625, 'Coso Medio c.1897', 'Imagen capturada en el tramo medio del Coso, donde un ceremonioso desfile de tropas de caballerâ”œآ،a queda enmarcado por el escâ”œآ®nico telâ”œâ”‚n de fondo edilicio de los nâ”œâ•‘meros 55 al 65, esquinero con la calle del Teatro, e incluso la casa que fuera de Simâ”œâ”‚n Ignacio Tarazona, desde 1875 sucursal del Banco de Espaâ”œâ–’a en Zaragoza. La fachada del Teatro Principal, aâ”œâ•‘n sin marquesina, resultado de la reforma acometida con proyecto de Ricardo Magdalena. Fuente visual: cesbor.blogspot.com.es/', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.65185700, -0.87969800, '0101000020E610000055698B6B7C26ECBF9755D80C70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39715644304.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39715644304.webp', 'https://www.flickr.com/photos/zaragozaantigua/39715644304/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23628, 'Coso Medio 1963', 'Veraniega imagen capturada hace 56 aâ”œâ–’os en el arranque del tramo medio del Coso, y centrada en el trolebâ”œâ•‘s Pegaso nâ”¬â•‘ 34 de la lâ”œآ،nea Barrio Jesâ”œâ•‘s estacionado en la terminal sita originalmente en esta ubicaciâ”œâ”‚n, y aâ”œâ–’os despuâ”œآ®s trasladada a la calle de la Verâ”œâ”‚nica. A la derecha circula un tranvâ”œآ،a de la serie 200, subserie de los "Rizados", en servicio en la lâ”œآ،nea 13. San Josâ”œآ®, que unos aâ”œâ–’os despuâ”œآ®s, junto con la lâ”œآ،nea 11. Parque, conformarâ”œآ،a la nueva lâ”œآ،nea 11. Parque-San Josâ”œآ®, la â”œâ•‘ltima de la histâ”œâ”‚rica red de tranvâ”œآ،as en ser desmantelada en 1976. Tras ellos, el desemboque de la calle de Los Sitios en el Coso Medio, que luce el aspecto de los antiguos inmuebles del nâ”¬â•‘ 54 al nâ”¬â•‘ 62. Tiempo despuâ”œآ®s, el nâ”¬â•‘ 54 serâ”œآ،a derribado e ingeniosamente adicionado al Banco de Espaâ”œâ–’a. Antes, los nâ”œâ•‘meros 56 y 62 serâ”œآ،an derribados para dar paso, con desigual resultado, a modernos, bien verticales y finos edificios de viviendas y oficinas comerciales. Al fondo y a la derecha se abre la plaza de Espaâ”œâ–’a.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.65171100, -0.87983900, '0101000020E6100000DCD9571EA427ECBFC3B81B446BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48290434971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48290434971.webp', 'https://www.flickr.com/photos/zaragozaantigua/48290434971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23631, 'Coso Medio c.1859', 'Imagen desde cierta altura del tramo del Coso Medio que al fondo arranca en la plaza de la Constituciâ”œâ”‚n. A la izquierda e inmediata, manzana comprendida entre la calle de los Sitios y la plaza, donde destacaba el Gran Hotel Restaurante de Europa. Al fondo, la Fuente de la Princesa mâ”œأ­s cerca del arranque del salâ”œâ”‚n de Santa Engracia. Entre el edificio de la Diputaciâ”œâ”‚n y el inmueble del nâ”¬â•‘ 1 de la plaza perdura un pequeâ”œâ–’o solar tapiado, recuerdo de un antiguo pasaje, que poco despuâ”œآ®s se anexarâ”œآ،a como ampliaciâ”œâ”‚n de su vecino nâ”¬â•‘ 1. A la derecha, el principio de la calle de Don Jaime I. El aspecto aparentemente despoblado indica que se trata de una de las primeras fotografâ”œآ،as tiradas en esta zona de la ciudad, bastante antes de la instalaciâ”œâ”‚n de las primeras lâ”œآ،neas de tranvâ”œآ،as tirados por caballerâ”œآ،as.', 1859, 1859, 1859, 'Siglo XIX', 'CENTRO', 41.65195900, -0.88002200, '0101000020E61000001D56B8E52329ECBF9BAA7B6473D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50859368266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50859368266.webp', 'https://www.flickr.com/photos/zaragozaantigua/50859368266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
